-- Schema for Domain: timesheet | Business: Staffing Hr | Version: v1_ecm
-- Generated on: 2026-05-02 15:53:31

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `staffing_hr_ecm`.`timesheet` COMMENT 'Owns all worker time and attendance data for contingent workers. Covers daily timesheet submission, hours worked, approval workflows, overtime (OT), double-time (DT), breaks, absences, PTO usage, per diem tracking, schedule management, and labor hour records sourced from Kronos Workforce Ready. Captures billable hours for client invoicing and payable hours for worker compensation. Feeds payroll processing and client billing with authoritative hours data.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`timesheet` (
    `timesheet_id` BIGINT COMMENT 'Unique system-generated identifier for the timesheet record. Primary key for the timesheet header entity representing a single worker-assignment-pay period combination. TRANSACTION_HEADER role — canonical primary key.',
    `assignment_id` BIGINT COMMENT 'Reference to the active placement or assignment under which the worker is performing services. Ties the timesheet to a specific job order, client, and pay/bill rate agreement. Essential for billing and payroll rate resolution.',
    `client_account_id` BIGINT COMMENT 'Reference to the client (end-customer) at whose site or under whose direction the worker performed services during this pay period. Used for client-level billing aggregation and SLA reporting.',
    `client_rate_card_id` BIGINT COMMENT 'Foreign key linking to client.rate_card. Business justification: Timesheets bill at rates defined in client rate cards; billing accuracy and rate card compliance audits require this link. Essential for bill rate validation, rate card compliance reporting, and margi',
    `contract_rate_schedule_id` BIGINT COMMENT 'Foreign key linking to contract.contract_rate_schedule. Business justification: Timesheets must validate bill/pay rates against contracted rate schedules for billing compliance and rate variance detection. Payroll and billing systems reconcile timesheet rates to contracted schedu',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Timesheets are charged to cost centers for client billing and internal P&L reporting. Staffing firms track profitability by cost center (client/project). Enables cost center variance analysis and clie',
    `credential_instance_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_instance. Business justification: Timesheet approval gates require verification that worker holds valid credentials for the assignment period. Staffing operations mandate credential compliance before hours are released to payroll/bill',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Timesheets drive GL postings for labor expense recognition under GAAP. Every approved timesheet posts to a GL account (typically labor expense) for financial statement preparation. Core to staffing fi',
    `i9_verification_id` BIGINT COMMENT 'Foreign key linking to compliance.i9_verification. Business justification: Timesheet approval and payroll processing require valid work authorization. Staffing firms must verify I-9 status before processing pay; expired work authorization blocks timesheet approval. Real busi',
    `invoice_id` BIGINT COMMENT 'Reference to the client invoice record in Salesforce Revenue Cloud to which this timesheets billable hours were applied. Enables timesheet-to-invoice traceability for billing reconciliation and revenue recognition. Populated after invoice generation; null prior to billing run.',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: Timesheets track work performed at specific client sites for location-based billing rates, state tax withholding, workers comp classification, and OSHA reporting. Essential for compliance and cost cen',
    `managed_program_id` BIGINT COMMENT 'Foreign key linking to client.managed_program. Business justification: Timesheets within managed programs follow program-specific SLAs and billing rules. Essential for managed program billing consolidation, program-level SLA measurement, and MSP fee calculation in staffi',
    `order_header_id` BIGINT COMMENT 'Reference to the job order (requisition) that originated the workers assignment. Enables timesheet-to-requisition traceability for workforce planning and fill-rate analytics.',
    `pay_run_id` BIGINT COMMENT 'Identifier of the payroll processing batch in TempWorks Payroll to which this approved timesheet was assigned. Enables traceability from the timesheet to the payroll run, supporting payroll reconciliation, reprocessing, and audit. Populated after payroll processing; null prior to payroll run.',
    `profile_id` BIGINT COMMENT 'Reference to the contingent worker who submitted this timesheet. Links to the worker/candidate master record in the staffing system. Supports payroll processing and worker-level labor analytics.',
    `staff_profile_id` BIGINT COMMENT 'Reference to the individual (supervisor, client manager, or VMS approver) who approved or rejected the timesheet. Supports approval audit trail, accountability reporting, and SLA measurement for time-to-approve KPI. Required for FLSA §516 recordkeeping and SOC 2 Type II audit compliance.',
    `vms_program_id` BIGINT COMMENT 'Foreign key linking to client.vms_program. Business justification: Timesheets submitted through VMS platforms require program-level routing and compliance tracking. Essential for VMS submission routing, program-specific approval workflows, and supplier performance me',
    `worker_classification_id` BIGINT COMMENT 'Foreign key linking to compliance.worker_classification. Business justification: Worker classification (W2 vs IC) determines tax withholding, OT eligibility, and bill rate markup on timesheets. Misclassification creates liability. Real business process: compliant rate calculation ',
    `approval_status` STRING COMMENT 'Current workflow state of the timesheet through the submission and approval lifecycle. Controls downstream payroll processing and client billing eligibility. draft = worker has not yet submitted; submitted = awaiting supervisor/client approval; approved = authorized for payroll and billing; rejected = returned to worker for correction; pending_review = escalated for secondary review; voided = cancelled and excluded from processing.. Valid values are `draft|submitted|approved|rejected|pending_review|voided`',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the timesheet was formally approved by the authorized approver (supervisor or client manager). Triggers eligibility for payroll processing and client billing. Null if not yet approved. Supports approval SLA measurement and audit compliance.',
    `bill_rate` DECIMAL(18,2) COMMENT 'Hourly bill rate (in USD) charged to the client for regular straight-time hours during this pay period. Sourced from the assignment/VMS rate card. Used by Salesforce Revenue Cloud to generate client invoices. Classified confidential as client pricing data.',
    `billable_hours` DECIMAL(18,2) COMMENT 'Total hours that are billable to the client for this pay period. Typically equals regular + OT + DT + holiday hours (excludes PTO and unpaid absences which are not client-billable). Authoritative input to Salesforce Revenue Cloud for client invoice generation. May differ from total_hours when non-billable paid time is present.',
    `break_hours` DECIMAL(18,2) COMMENT 'Total unpaid break time (meal periods) recorded during the pay period. Tracked to support state-mandated meal and rest break compliance (California IWC Wage Orders, Washington WAC 296-126-092, Oregon ORS 653.261). Ensures break deductions are correctly applied to gross hours to derive net payable hours.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when the timesheet record was first created in Kronos Workforce Ready. Represents the audit record creation event. Required for FLSA §516 minimum 3-year retention compliance and SOC 2 Type II audit trail.',
    `dt_hours` DECIMAL(18,2) COMMENT 'Total double-time hours worked during the pay period. Applicable under state-specific laws (e.g., California Labor Code §510 — hours over 12 in a day or all hours on the 7th consecutive day). Billed at the DT bill rate and paid at 2x the regular pay rate. Null or zero in jurisdictions without DT requirements.',
    `expense_amount` DECIMAL(18,2) COMMENT 'Total approved expense reimbursements (in USD) for the pay period beyond per diem (e.g., mileage, tools, uniforms). Payable to the worker and potentially billable to the client per MSA terms. Tracked separately from wages for payroll and billing accuracy.',
    `flsa_classification` STRING COMMENT 'Workers FLSA classification for this assignment: exempt (not entitled to OT under FLSA salary/duties tests) or non_exempt (entitled to OT at 1.5x for hours over 40/week). Drives overtime eligibility logic in payroll processing. Subject to DOL enforcement and IRS worker classification rules.. Valid values are `exempt|non_exempt`',
    `holiday_hours` DECIMAL(18,2) COMMENT 'Hours worked on designated company or client-observed holidays during the pay period. May be billed at a premium holiday bill rate and paid at a holiday pay rate per the assignment agreement or client MSA. Tracked separately for accurate payroll and billing rate application.',
    `is_disputed` BOOLEAN COMMENT 'Flag indicating whether the timesheet has been formally disputed by the worker, client, or staffing firm. Triggers a dispute resolution workflow and places a hold on payroll processing and client billing until resolved. Supports dispute rate KPI and compliance audit.',
    `is_late_submission` BOOLEAN COMMENT 'Flag indicating whether the worker submitted the timesheet after the client or staffing firms defined submission deadline for the pay period. Used for late submission rate KPI reporting, worker compliance tracking, and payroll processing delay root cause analysis.',
    `kronos_timesheet_ref` STRING COMMENT 'Native timesheet identifier from the Kronos Workforce Ready source system. Enables direct traceability from the Silver layer record back to the operational system of record for audit, reconciliation, and support purposes.',
    `meal_break_waiver` BOOLEAN COMMENT 'Flag indicating whether the worker signed a valid meal break waiver for this pay period, as permitted under California IWC Wage Orders for shifts of 6 hours or less, or mutual consent waivers for second meal periods. Required for California, Oregon, and Washington meal break compliance documentation. Null for non-applicable jurisdictions.',
    `ot_bill_rate` DECIMAL(18,2) COMMENT 'Hourly bill rate (in USD) charged to the client for overtime hours. Typically 1.5x the regular bill rate per the client MSA or VMS rate card. Used by Salesforce Revenue Cloud for OT billing line generation.',
    `ot_hours` DECIMAL(18,2) COMMENT 'Total overtime hours worked during the pay period, typically hours exceeding 40 in a workweek under FLSA federal rules, or daily thresholds under state law (e.g., California 8-hour daily OT rule). Billed at the OT bill rate and paid at 1.5x the regular pay rate. Critical for FLSA §207 compliance and accurate payroll/billing.',
    `ot_pay_rate` DECIMAL(18,2) COMMENT 'Hourly pay rate (in USD) applied to overtime hours. Typically 1.5x the regular pay rate per FLSA §207. May vary by state law or assignment agreement. Used by TempWorks Payroll for OT gross wage calculation.',
    `pay_period_end_date` DATE COMMENT 'Last calendar date of the pay period covered by this timesheet. Defines the closing boundary for hours worked. Used in conjunction with pay_period_start_date for FLSA compliance, payroll cutoff, and billing period matching.',
    `pay_period_start_date` DATE COMMENT 'First calendar date of the pay period covered by this timesheet. Combined with pay_period_end_date defines the authoritative date range for hours worked, used for FLSA overtime calculation, payroll processing, and client invoice period alignment.',
    `pay_period_type` STRING COMMENT 'Frequency classification of the pay period covered by this timesheet. Determines payroll processing schedule and FLSA workweek overtime calculation methodology. weekly = 7-day period; biweekly = 14-day period; semi_monthly = twice per month; monthly = full calendar month.. Valid values are `weekly|biweekly|semi_monthly|monthly`',
    `pay_rate` DECIMAL(18,2) COMMENT 'Hourly pay rate (in USD) at which the worker is compensated for regular straight-time hours during this pay period. Sourced from the assignment agreement. Used by TempWorks Payroll to calculate gross wages. Subject to FLSA minimum wage compliance and state minimum wage laws. Classified confidential as worker compensation data.',
    `per_diem_amount` DECIMAL(18,2) COMMENT 'Total per diem reimbursement amount (in USD) for the pay period, covering meals, lodging, and incidental expenses for workers on travel assignments. Non-taxable up to IRS GSA per diem rates. Payable to the worker but may or may not be billable to the client depending on the MSA. Tracked separately from wages for IRS tax treatment.',
    `pto_hours` DECIMAL(18,2) COMMENT 'Hours of paid time off (PTO) used by the worker during the pay period. Includes vacation, sick leave, and other approved paid absences. Payable but not billable to the client. Tracked for PTO balance management and payroll cost allocation. Subject to state-mandated paid sick leave laws (e.g., California SB 3, Washington ESSB 5975).',
    `regular_hours` DECIMAL(18,2) COMMENT 'Total straight-time (non-overtime, non-double-time) hours worked by the worker during the pay period. Represents the base billable and payable hours at the standard pay rate and bill rate. Core input to payroll gross pay calculation and client invoice generation. Subject to FLSA §207 threshold monitoring.',
    `rejection_reason` STRING COMMENT 'Free-text or coded reason provided by the approver when a timesheet is rejected. Captures the basis for rejection (e.g., hours discrepancy, missing punch, unauthorized OT, incorrect cost center). Supports worker correction guidance, rejection pattern analysis, and audit documentation.',
    `submitted_timestamp` TIMESTAMP COMMENT 'Date and time when the worker electronically submitted the timesheet for approval. Represents the principal business event timestamp for the timesheet lifecycle. Used for SLA tracking (time-to-approve), late submission reporting, and audit trail under FLSA §516 recordkeeping requirements.',
    `timesheet_number` STRING COMMENT 'Human-readable, externally visible timesheet reference number used in worker communications, client invoices, and payroll remittances. Sourced from Kronos Workforce Ready and carried through to billing and payroll systems.. Valid values are `^TS-[0-9]{4}-[0-9]{6}$`',
    `total_hours` DECIMAL(18,2) COMMENT 'Sum of all compensable hours for the pay period: regular + OT + DT + holiday + PTO hours. Represents the total payable hours used as the basis for gross pay calculation. Excludes unpaid break hours and unpaid absences. Authoritative hours figure fed to TempWorks Payroll for payroll processing.',
    `unpaid_absence_hours` DECIMAL(18,2) COMMENT 'Hours of unpaid absence recorded during the pay period (e.g., unexcused absences, unpaid leave). Not billable to the client and not payable to the worker. Tracked for attendance management, assignment compliance monitoring, and potential assignment termination triggers.',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to the timesheet record. Tracks any changes post-creation including corrections, re-submissions, or approval status changes. Supports change data capture (CDC) in the Databricks Silver layer and audit compliance.',
    `vms_timesheet_ref` STRING COMMENT 'External timesheet identifier assigned by the clients Vendor Management System (e.g., Beeline VMS) when the client manages contingent labor through a VMS program. Used for cross-system reconciliation between the staffing firms Kronos records and the clients VMS approval records. Null for non-VMS-managed assignments.',
    `work_order_number` STRING COMMENT 'Client-issued work order or purchase order number associated with the workers assignment for this pay period. Required on client invoices for accounts payable matching. Sourced from the clients procurement or VMS system. Null if the client does not require PO-based billing.',
    `worker_type` STRING COMMENT 'Classification of the workers engagement type for this timesheet period. Determines tax treatment, payroll processing path, and co-employment risk profile. w2_temp = W-2 temporary employee; w2_contract = W-2 contract worker; 1099_ic = Independent Contractor (1099); corp_to_corp = C2C vendor engagement; eor = Employer of Record arrangement. [ENUM-REF-CANDIDATE: w2_temp|w2_contract|1099_ic|corp_to_corp|eor — promote to reference product]. Valid values are `w2_temp|w2_contract|1099_ic|corp_to_corp|eor`',
    CONSTRAINT pk_timesheet PRIMARY KEY(`timesheet_id`)
) COMMENT 'Core master record for a workers timesheet submission covering a defined pay period. Represents the authoritative timesheet header sourced from Kronos Workforce Ready, capturing the worker, assignment, client, pay period dates, submission status, total regular hours, OT hours, DT hours, per diem, approval state, and audit timestamps. This is the SSOT for all billable and payable hours for a given worker-assignment-period combination. Subject to FLSA §516 recordkeeping requirements (minimum 3-year retention of hours worked, wages paid, and conditions of employment). Supports state-specific meal/rest break compliance tracking for California, Washington, Oregon, and other jurisdictions with mandatory break laws.';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`time_entry` (
    `time_entry_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying a single shift-level or daily time entry record. Primary key for the time_entry product. Entity role: TRANSACTION_LINE — granular child record of a timesheet header representing one worked period.',
    `assignment_id` BIGINT COMMENT 'Reference to the active placement or assignment under which this time entry is recorded. Ties the worked hours to the specific job order, client, and bill/pay rate agreement governing this engagement.',
    `client_account_id` BIGINT COMMENT 'Reference to the client (end-customer) at whose worksite the hours were worked. Used for client billing, SLA reporting, and workforce analytics segmented by client account.',
    `contract_rate_schedule_id` BIGINT COMMENT 'Foreign key linking to contract.contract_rate_schedule. Business justification: Individual time entries inherit rate schedules from assignments; payroll and billing systems validate each entrys bill/pay rates against contracted schedules. Real business process: line-item rate va',
    `credential_instance_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_instance. Business justification: Individual time entries must validate worker credentials to determine billable/payable status. Expired credentials make hours non-billable in VMS programs. Critical for per-entry compliance auditing i',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Individual time entries may post to different GL accounts based on labor category, shift differential, or client contract terms. Required for detailed expense classification and multi-GL timesheet sce',
    `labor_category_id` BIGINT COMMENT 'Foreign key linking to timesheet.labor_category. Business justification: time_entry currently has labor_category as STRING code. Should FK to labor_category.labor_category_id for authoritative labor category definition including rates, FLSA classification, and billing rule',
    `profile_id` BIGINT COMMENT 'Reference to the contingent worker whose time is being recorded. Satisfies TRANSACTION_LINE RESOURCE_REFERENCE category. Links to the worker master record for pay rate, classification, and compliance lookups.',
    `staff_profile_id` BIGINT COMMENT 'Reference to the supervisor, manager, or client approver who approved this time entry. Required for the approval workflow audit trail and to satisfy FLSA §516 recordkeeping requirements that time records be verified by an authorized representative.',
    `timesheet_id` BIGINT COMMENT 'Foreign key reference to the parent timesheet header record that groups this time entry within a pay period. Satisfies TRANSACTION_LINE HEADER_REFERENCE category. Required for payroll aggregation and client billing rollup.',
    `wage_hour_determination_id` BIGINT COMMENT 'Foreign key linking to compliance.wage_hour_determination. Business justification: Each time entry must comply with FLSA/state wage-hour rules. OT calculation, meal break compliance, and minimum wage validation depend on wage-hour determination. Real business process: compliant time',
    `work_location_id` BIGINT COMMENT 'Reference to the physical client worksite location where the hours were worked. Required for workers compensation premium calculation (state and class code), OSHA recordkeeping, and multi-state payroll tax jurisdiction determination.',
    `absence_reason_code` STRING COMMENT 'Standardized code indicating the reason for any absence or non-worked time within this entry period (e.g., SICK, FMLA, JURY, BEREAVEMENT, NO_SHOW, WEATHER). Null when the worker was present for the full scheduled shift. Required for FMLA tracking and workforce attendance analytics. [ENUM-REF-CANDIDATE: sick|fmla|jury_duty|bereavement|no_show|weather|personal|military — promote to reference product]',
    `actual_end_time` TIMESTAMP COMMENT 'The actual clock-out date-time for the worked period. Paired with actual_start_time and break_duration_minutes to compute net hours worked. Required for FLSA §516 and California Labor Code §226 itemized wage statement backing data.',
    `actual_start_time` TIMESTAMP COMMENT 'The actual clock-in date-time for the worked period as captured by Kronos (badge swipe, biometric, mobile punch, or manual entry). Used for attendance analysis, late-arrival tracking, and FLSA recordkeeping.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when this time entry was approved by the authorized approver. Distinct from submission and creation timestamps. Required for SLA measurement (time-to-approve) and FLSA §516 audit trail.',
    `bill_rate` DECIMAL(18,2) COMMENT 'The hourly bill rate (in USD) charged to the client for this time entry. Captured at entry level to preserve the contractual rate-in-effect. Used by Salesforce Revenue Cloud to generate client invoices. The spread (bill_rate − pay_rate) drives gross margin reporting.',
    `break_duration_minutes` STRING COMMENT 'Total unpaid break time in minutes deducted from the gross shift duration to arrive at net hours worked. Includes all meal and rest break periods. Required for accurate net hours calculation and California Labor Code §512 meal period compliance.',
    `cost_center_code` STRING COMMENT 'Client or internal cost center code to which the labor hours are allocated for billing and financial reporting. Sourced from the clients organizational hierarchy in Beeline VMS or Salesforce Revenue Cloud. Enables cost allocation reporting in Oracle NetSuite ERP.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this time entry record was first created in the source system (Kronos Workforce Ready). Satisfies RECORD_AUDIT_CREATED category. Used for data lineage, ETL watermarking, and audit trail.',
    `entry_date` DATE COMMENT 'The calendar date on which the worked period occurred (yyyy-MM-dd). Serves as the primary business event date for this time entry. Used for daily labor reporting, schedule variance analysis, and FLSA workweek calculations. Satisfies TRANSACTION_LINE LINE_SEQUENCE anchor date.',
    `entry_source` STRING COMMENT 'The method or system through which this time entry was captured: Kronos hardware clock (badge/biometric), Kronos mobile app, manual supervisor entry, VMS import from Beeline, or supervisor-entered correction. Supports audit trail requirements and data quality monitoring.. Valid values are `kronos_clock|mobile|manual|vms_import|supervisor_entry`',
    `entry_status` STRING COMMENT 'Current workflow lifecycle state of the time entry record. Controls whether the entry is editable, pending approval, approved for payroll/billing processing, rejected for correction, voided, or locked after payroll run. Satisfies TRANSACTION_LINE LINE_VALUE_OR_RESULT lifecycle dimension.. Valid values are `draft|submitted|approved|rejected|voided|locked`',
    `flsa_exempt` BOOLEAN COMMENT 'Indicates whether the worker is classified as FLSA-exempt (True) for this engagement, meaning overtime pay requirements under FLSA §207 do not apply. False for non-exempt workers who are entitled to OT at 1.5x for hours exceeding 40 per workweek. Critical for correct OT calculation in payroll.',
    `is_billable` BOOLEAN COMMENT 'Indicates whether the hours in this time entry are billable to the client. False for internal training time, orientation hours, or non-billable absence periods. Drives inclusion/exclusion in Salesforce Revenue Cloud invoice generation.',
    `is_payable` BOOLEAN COMMENT 'Indicates whether the hours in this time entry are payable to the worker. May differ from is_billable in cases such as orientation (payable but not billable) or disputed hours (billable but payment withheld pending resolution). Drives TempWorks Payroll gross pay inclusion.',
    `job_code` STRING COMMENT 'Standardized job classification code identifying the role or position being performed during this time entry. Aligns with the job orders position code and is used for EEOC reporting, OFCCP compliance, and workforce analytics by job classification.',
    `kronos_punch_ref` STRING COMMENT 'Source system identifier from Kronos Workforce Ready linking this time entry back to the originating raw punch event record. Enables drill-through from the Silver layer aggregated entry to the raw punch event for audit and dispute resolution. Null for manually entered records.',
    `labor_category` STRING COMMENT 'Classification of the type of work performed during this entry (e.g., Light Industrial, IT Professional, Healthcare, Administrative, Engineering). Used for workforce analytics, cost allocation, and Beeline VMS rate card alignment. [ENUM-REF-CANDIDATE: light_industrial|it_professional|healthcare|administrative|engineering|skilled_trades|clerical|professional — promote to reference product]',
    `line_sequence` STRING COMMENT 'Sequential ordering number of this time entry within its parent timesheet header. Enables ordered display and processing of multiple daily entries within a single timesheet period. Satisfies TRANSACTION_LINE LINE_SEQUENCE category.',
    `meal_break_compliant` BOOLEAN COMMENT 'Indicates whether the required meal break was taken in compliance with applicable state law (e.g., California Labor Code §512 requires a 30-minute unpaid meal period for shifts exceeding 5 hours). True = compliant; False = potential violation requiring premium pay or legal review.',
    `modified_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to this time entry record. Satisfies RECORD_AUDIT_UPDATED category. Tracks corrections, retroactive adjustments, and re-approvals. Essential for change data capture (CDC) in the Databricks Silver layer pipeline.',
    `net_hours_worked` DECIMAL(18,2) COMMENT 'Actual compensable hours worked during this entry period, computed as (actual_end_time − actual_start_time) − break_duration_minutes, expressed in decimal hours. Satisfies TRANSACTION_LINE LINE_QUANTITY category. This is the authoritative hours figure fed to payroll and client billing. Subject to FLSA §516 recordkeeping.',
    `pay_rate` DECIMAL(18,2) COMMENT 'The hourly pay rate (in USD) applicable to this time entry for worker compensation. Captured at the entry level to preserve the rate-in-effect at time of work, which may differ from the current placement rate due to retroactive adjustments or mid-period rate changes. Feeds TempWorks Payroll gross pay calculation. Satisfies TRANSACTION_LINE LINE_VALUE_OR_RESULT monetary dimension.',
    `pay_type` STRING COMMENT 'Classification of the hours worked for compensation purposes: regular straight-time (REG), overtime at 1.5x (OT), double-time at 2x (DT), holiday premium, per diem allowance, or paid time off (PTO). Drives the pay rate multiplier applied in TempWorks Payroll and the bill rate applied in Salesforce Revenue Cloud.. Valid values are `regular|overtime|double_time|holiday|per_diem|pto`',
    `per_diem_amount` DECIMAL(18,2) COMMENT 'Per diem allowance amount (in USD) associated with this time entry for travel, lodging, or meal reimbursement when the worker is on a remote or travel assignment. Tracked separately from wages for IRS per diem tax treatment. Zero if no per diem applies.',
    `pto_hours` DECIMAL(18,2) COMMENT 'Number of paid time off (PTO) hours applied to this entry when the worker is absent but entitled to paid leave. Distinct from net_hours_worked (which reflects physically worked hours). Feeds PTO balance deduction in SAP SuccessFactors and payroll processing in TempWorks.',
    `rejection_reason` STRING COMMENT 'Free-text or coded reason provided by the approver when a time entry is rejected (entry_status = rejected). Documents the basis for rejection to guide worker or supervisor correction. Null when entry is not in rejected status.',
    `rest_break_compliant` BOOLEAN COMMENT 'Indicates whether all required paid rest breaks were provided in compliance with applicable state law (e.g., California IWC Wage Orders require a 10-minute paid rest period for every 4 hours worked). True = compliant; False = potential premium pay obligation.',
    `schedule_variance_hours` DECIMAL(18,2) COMMENT 'Delta between planned hours (derived from scheduled_start_time and scheduled_end_time) and actual net_hours_worked for this entry. Positive value indicates overtime relative to schedule; negative indicates early departure or absence. Key KPI for workforce scheduling compliance and dispatch analytics.',
    `scheduled_end_time` TIMESTAMP COMMENT 'The planned shift end date-time as defined in the workers schedule. Paired with scheduled_start_time to derive planned shift duration for schedule variance and workforce planning analytics.',
    `scheduled_start_time` TIMESTAMP COMMENT 'The planned shift start date-time as defined in the workers schedule in Kronos Workforce Ready. Used to compute schedule variance (planned vs. actual hours delta) and to assess punctuality and dispatch compliance.',
    `shift_differential_code` STRING COMMENT 'Alphanumeric code identifying the applicable shift differential pay rule (e.g., EVE15, NIGHT20, WKD10). Maps to the differential rate table in TempWorks Payroll to apply the correct premium multiplier to base pay rate. Distinct from shift_type which is a broad category.',
    `shift_type` STRING COMMENT 'Categorical classification of the shift period for differential pay and workforce scheduling analytics. Day, evening, night, weekend, and holiday shifts may carry different pay and bill rate differentials per the client MSA or worker agreement.. Valid values are `day|evening|night|weekend|holiday`',
    `state_code` STRING COMMENT 'Two-letter US state code (e.g., CA, NY, TX) identifying the state where the work was physically performed. Determines applicable state wage and hour laws, state income tax withholding jurisdiction, SUTA rate, and state-specific break and overtime rules. Critical for multi-state payroll compliance.',
    `submitted_timestamp` TIMESTAMP COMMENT 'Date and time when the worker or supervisor submitted this time entry for approval. Satisfies TRANSACTION_LINE BUSINESS_EVENT_TIMESTAMP category. Used to measure submission timeliness against payroll cutoff deadlines and SLA compliance.',
    `vms_time_entry_ref` STRING COMMENT 'External reference identifier assigned by the clients Vendor Management System (VMS), such as Beeline, for this time entry when the client manages contingent labor through a VMS program. Enables reconciliation between Staffing Hrs internal records and the clients VMS for invoice matching and dispute resolution.',
    `workers_comp_class_code` STRING COMMENT 'NCCI or state-specific workers compensation classification code applicable to the work performed during this entry. Determined by the job type and worksite state. Used by TempWorks Payroll to calculate workers comp premium allocation and for state insurance reporting.',
    CONSTRAINT pk_time_entry PRIMARY KEY(`time_entry_id`)
) COMMENT 'Granular daily or shift-level time record representing a single worked period for a contingent worker. This is the unified SSOT for all shift-level and daily worked-time data — there is no separate shift product. Captures the specific date, planned and actual start/end times, break duration, meal break compliance flag, rest break compliance flag, net hours worked, pay type (regular, OT, DT), shift differential code, shift type (day/evening/night/weekend), labor category, cost center, schedule variance (planned vs actual hours delta), and entry source (Kronos clock, mobile, manual). Child record of the timesheet header. Incorporates shift-level schedule comparison, shift differential tracking, and dispatch-relevant shift metadata. Feeds both payroll and billing calculations. Links raw punch events to the timesheet summary. Subject to FLSA §516 and state-specific recordkeeping requirements including California Labor Code §226 (itemized wage statement backing data).';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`timesheet_approval_workflow` (
    `timesheet_approval_workflow_id` BIGINT COMMENT 'Unique system-generated identifier for each timesheet approval workflow record. Serves as the primary key for this entity. Role: TRANSACTION_HEADER — tracks the multi-step approval lifecycle for a single timesheet submission.',
    `assignment_id` BIGINT COMMENT 'Reference to the worker placement or assignment associated with this timesheet approval workflow. Ties the approval to the specific contingent worker assignment and client engagement.',
    `client_account_id` BIGINT COMMENT 'Reference to the client organization for whom the contingent worker performed services. Used to route approval to the correct client contact and enforce client-specific SLA rules.',
    `client_contact_id` BIGINT COMMENT 'Foreign key linking to client.contact. Business justification: Client-side timesheet approvers are contacts; approval routing, SLA tracking, and audit trails require knowing which client contact approved hours. Critical for dispute resolution and compliance audit',
    `pay_period_id` BIGINT COMMENT 'Reference to the payroll pay period to which the approved timesheet hours will be applied. Links the approval workflow to downstream payroll processing and ensures hours are captured in the correct pay cycle.',
    `staff_profile_id` BIGINT COMMENT 'Reference to the individual (supervisor, client contact, or back-office auditor) who performed the approval action at this workflow stage. Enables full audit trail of approver identity.',
    `profile_id` BIGINT COMMENT 'Reference to the contingent worker (candidate) who submitted the timesheet being reviewed in this approval workflow. Supports worker-level audit trail and dispute resolution.',
    `tertiary_timesheet_delegated_approver_staff_profile_id` BIGINT COMMENT 'Reference to the individual who acted on behalf of the primary approver when delegation was in effect (e.g., during leave or absence). Populated only when approval_action is delegated. Supports audit trail integrity.',
    `timesheet_id` BIGINT COMMENT 'Reference to the parent timesheet record for which this approval workflow instance was initiated. Links the approval workflow to the specific worker time submission being reviewed.',
    `action_timestamp` TIMESTAMP COMMENT 'The exact date and time when the approver performed the approval action at this workflow stage. Serves as the principal business event timestamp for this transaction. Critical for SLA compliance measurement and audit trail.',
    `approval_action` STRING COMMENT 'The specific action taken by the approver at this workflow stage. Distinct from approval_status in that it captures the discrete action event (e.g., delegated) rather than the resulting state. Used for audit trail and workflow analytics.. Valid values are `approved|rejected|escalated|auto_approved|recalled|delegated`',
    `approval_channel` STRING COMMENT 'The interface or channel through which the approver submitted their approval action. Supports channel adoption analytics and helps identify approval bottlenecks by channel type.. Valid values are `web_portal|mobile_app|vms_portal|email|api|auto_system`',
    `approval_stage` STRING COMMENT 'The specific step in the multi-stage approval workflow at which this record applies. Stages include worker submission, supervisor review, client approval, back-office audit, and payroll release. Each stage represents a distinct checkpoint in the timesheet lifecycle.. Valid values are `worker_submission|supervisor_review|client_approval|back_office_audit|payroll_release`',
    `approval_status` STRING COMMENT 'Current lifecycle state of this approval workflow stage. Indicates whether the stage is awaiting action (pending), has been approved, rejected, escalated to a higher authority, auto-approved per system rules, or recalled by the submitter.. Valid values are `pending|approved|rejected|escalated|auto_approved|recalled`',
    `approver_role` STRING COMMENT 'The functional role of the approver at this workflow stage. Distinguishes between worker self-submission, direct supervisor review, client manager approval, back-office audit, payroll admin release, and MSP coordinator oversight.. Valid values are `worker|supervisor|client_manager|back_office_auditor|payroll_admin|msp_coordinator`',
    `auto_approval_rule_code` STRING COMMENT 'Identifier of the system-defined auto-approval rule that triggered automatic approval of this timesheet stage without manual intervention. Populated only when approval_action is auto_approved. Enables audit of automated decisions.',
    `bill_rate` DECIMAL(18,2) COMMENT 'The hourly rate at which the client is billed for the workers time as defined in the client contract or VMS program. Used to validate that approved hours will generate the correct client invoice amount.',
    `billing_released_flag` BOOLEAN COMMENT 'Indicates whether the approved timesheet hours have been released to the client billing system (Salesforce Revenue Cloud) for invoice generation. Enables reconciliation between approved hours and billed hours.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this approval workflow record was first created in the system. Serves as the audit creation timestamp for data lineage and SOC 2 compliance purposes.',
    `dispute_flag` BOOLEAN COMMENT 'Indicates whether this timesheet approval workflow record is associated with a formal dispute raised by the worker, client, or staffing agency. When True, the record is flagged for dispute resolution review and may be excluded from standard payroll processing until resolved.',
    `dispute_reference_number` STRING COMMENT 'The case or ticket number associated with a formal timesheet dispute. Populated when dispute_flag is True. Used to link the approval workflow record to the dispute management process for resolution tracking.',
    `escalation_reason` STRING COMMENT 'Free-text or coded explanation for why this approval stage was escalated to a higher authority. Populated when approval_action is escalated. Supports escalation pattern analysis and workflow optimization.',
    `final_approved_flag` BOOLEAN COMMENT 'Indicates whether this workflow record represents the final, fully-approved state of the timesheet across all required approval stages. When True, the timesheet is cleared for payroll processing and client billing. Enables efficient filtering for downstream payroll and billing feeds.',
    `kronos_timesheet_ref` STRING COMMENT 'The source system reference identifier from Kronos Workforce Ready for the timesheet record associated with this approval workflow. Supports data lineage tracing and reconciliation with the system of record.',
    `pay_rate` DECIMAL(18,2) COMMENT 'The hourly rate at which the contingent worker is compensated for approved hours. Used to validate payroll calculations downstream. The spread (bill_rate minus pay_rate) represents gross margin.',
    `payroll_released_flag` BOOLEAN COMMENT 'Indicates whether the approved timesheet hours have been released to the payroll processing system (TempWorks Payroll) for worker compensation. Distinct from final_approved_flag as it confirms the downstream handoff has occurred.',
    `per_diem_amount` DECIMAL(18,2) COMMENT 'The total per diem dollar amount claimed by the worker on this timesheet. Populated when per_diem_claimed is True. Subject to IRS per diem rate limits and client contract terms. Feeds into billing and payroll calculations.',
    `per_diem_claimed` BOOLEAN COMMENT 'Indicates whether the worker claimed a per diem allowance (daily expense reimbursement for travel, meals, or lodging) on this timesheet. Per diem claims require separate approval validation against the assignment agreement.',
    `rejection_reason_code` STRING COMMENT 'Standardized code indicating the reason the timesheet was rejected at this approval stage. Used for root-cause analysis of rejection patterns and worker coaching. Populated only when approval_action is rejected. [ENUM-REF-CANDIDATE: hours_discrepancy|missing_entries|unauthorized_overtime|unapproved_per_diem|policy_violation|duplicate_submission|other — promote to reference product]',
    `rejection_reason_notes` STRING COMMENT 'Free-text narrative provided by the approver explaining the specific reason for rejecting the timesheet at this stage. Supplements the rejection_reason_code with contextual detail for dispute resolution and worker communication.',
    `resubmission_count` STRING COMMENT 'The number of times the worker has resubmitted this timesheet after a rejection. A high resubmission count indicates recurring errors or disputes and is used for quality-of-submission (QoS) analytics and worker coaching.',
    `sla_breach_minutes` STRING COMMENT 'The number of minutes by which the approval action exceeded the SLA deadline. Populated only when sla_compliant_flag is False. Zero or null when SLA was met. Enables severity-based SLA breach analysis and client reporting.',
    `sla_compliant_flag` BOOLEAN COMMENT 'Indicates whether the approval action was completed within the SLA-defined deadline for this stage. True if the action_timestamp is on or before sla_due_timestamp; False if the SLA was breached. Supports SLA compliance reporting and client KPI dashboards.',
    `sla_due_timestamp` TIMESTAMP COMMENT 'The contractually or operationally defined deadline by which this approval stage must be completed per the applicable SLA. Derived from the SLA configuration for the client or program. Used to calculate SLA compliance.',
    `stage_sequence_number` STRING COMMENT 'Numeric ordering of this approval stage within the overall workflow. Enables reconstruction of the full approval chain in chronological order and supports multi-step workflow analytics.',
    `submission_timestamp` TIMESTAMP COMMENT 'The date and time when the worker originally submitted the timesheet that triggered this approval workflow. Used as the baseline for SLA elapsed time calculations and Time-to-Approve (TTA) reporting.',
    `total_dt_hours` DECIMAL(18,2) COMMENT 'Total number of double-time (DT) hours recorded on the timesheet, applicable in jurisdictions or contracts where hours beyond a threshold (e.g., 12 hours/day or 7th consecutive day) are compensated at double the regular rate.',
    `total_ot_hours` DECIMAL(18,2) COMMENT 'Total number of overtime (OT) hours recorded on the timesheet, typically hours worked beyond 40 per week or 8 per day per FLSA or applicable state law. Requires explicit approval and is a common rejection trigger.',
    `total_regular_hours` DECIMAL(18,2) COMMENT 'Total number of straight-time (non-overtime) hours recorded on the timesheet being reviewed in this approval workflow. Used to validate hours against scheduled hours and client purchase order limits.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this approval workflow record was last modified. Tracks the most recent state change for audit trail purposes and supports incremental data pipeline processing.',
    `vms_workflow_ref` STRING COMMENT 'The external workflow identifier assigned by the Vendor Management System (VMS), such as Beeline, for this timesheet approval transaction. Enables cross-system reconciliation between the internal approval record and the clients VMS portal.',
    `work_week_end_date` DATE COMMENT 'The last day of the work week covered by the timesheet being approved. Used to align the approval workflow with payroll processing cycles and client billing periods.',
    `workflow_instance_number` STRING COMMENT 'Externally-known business identifier for this approval workflow instance, used in communications, dispute resolution, and audit references. Typically formatted as a sequential or alphanumeric code (e.g., WF-2024-00123).',
    CONSTRAINT pk_timesheet_approval_workflow PRIMARY KEY(`timesheet_approval_workflow_id`)
) COMMENT 'Tracks the multi-step approval workflow lifecycle for a timesheet submission. Captures each approval stage (worker submission, supervisor review, client approval, back-office audit), the approver identity, approval action (approved, rejected, escalated, auto-approved), action timestamp, rejection reason, and SLA compliance flag. Enables full audit trail of who approved what and when, supporting dispute resolution and compliance requirements.';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`absence_record` (
    `absence_record_id` BIGINT COMMENT 'Unique system-generated identifier for each absence record. Primary key for the absence_record data product within the timesheet domain.',
    `assignment_id` BIGINT COMMENT 'Identifier of the active placement or assignment during which the absence occurred. Used to associate the absence with the specific client engagement and job order.',
    `client_account_id` BIGINT COMMENT 'Identifier of the client organization at whose worksite the worker was assigned when the absence occurred. Used for client SLA compliance tracking and notification workflows.',
    `i9_verification_id` BIGINT COMMENT 'Foreign key linking to compliance.i9_verification. Business justification: Extended absences may trigger work authorization re-verification, especially for visa holders with expiring EADs. Staffing firms must track I-9 status during leave. Real business process: work authori',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: Absences impact client site staffing levels and trigger replacement workflows; site managers need absence visibility for scheduling. Essential for client site headcount management and replacement requ',
    `profile_id` BIGINT COMMENT 'Identifier of the contingent worker associated with this absence record. Links to the worker master record in the workforce management system.',
    `pto_accrual_id` BIGINT COMMENT 'Foreign key linking to payroll.pto_accrual. Business justification: Absence records consume PTO balances tracked in pto_accrual. This link enables leave balance reconciliation, ensures absence hours deducted match accrual transactions, and supports audit of PTO usage ',
    `timesheet_id` BIGINT COMMENT 'Identifier of the timesheet record for the pay period in which this absence falls. Links the absence to the authoritative hours record for payroll and billing.',
    `absence_duration_days` DECIMAL(18,2) COMMENT 'Total calendar duration of the absence expressed in days (may be fractional for partial-day absences). Derived from absence_start_date and absence_end_date but stored for reporting efficiency and workforce availability analytics.',
    `absence_end_date` DATE COMMENT 'The last calendar date of the absence period. Null for open-ended absences (e.g., ongoing FMLA leave). Combined with absence_start_date to determine total absence duration.',
    `absence_hours` DECIMAL(18,2) COMMENT 'Total number of scheduled work hours missed during the absence period. Used for payroll deduction calculations, PTO balance consumption, and workforce availability reporting.',
    `absence_notes` STRING COMMENT 'Free-text notes entered by the worker, manager, or HR coordinator providing additional context for the absence (e.g., nature of illness, family emergency details). Classified as confidential due to potential sensitivity of leave-related information.',
    `absence_reference_number` STRING COMMENT 'Externally visible, human-readable reference number assigned to this absence record (e.g., ABS-2024-00123). Used in worker communications, manager approvals, and leave management correspondence.',
    `absence_start_date` DATE COMMENT 'The first calendar date of the absence period. Used to calculate absence duration, determine pay period impact, and trigger FMLA tracking windows.',
    `absence_type` STRING COMMENT 'Classification of the absence by leave category as defined in the leave management policy. Drives payroll treatment (paid vs. unpaid), compliance recordkeeping, and workforce availability reporting. [ENUM-REF-CANDIDATE: PTO|Sick Leave|FMLA|Holiday|Jury Duty|Bereavement|Unexcused|Personal|Military|Workers Comp — promote to reference product]',
    `approval_status` STRING COMMENT 'Current workflow state of the absence request through the manager approval process. Drives payroll processing eligibility and client notification triggers. Pending = submitted awaiting review; Approved = manager authorized; Denied = rejected; Cancelled = worker withdrew; Under Review = escalated.. Valid values are `Pending|Approved|Denied|Cancelled|Under Review`',
    `approved_by` STRING COMMENT 'Name or system identifier of the manager, supervisor, or automated workflow that approved or denied the absence request. Supports audit trail and accountability for leave decisions.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the absence request was approved or denied by the authorized approver. Null if still pending. Used for approval workflow SLA tracking and audit trail.',
    `client_notification_timestamp` TIMESTAMP COMMENT 'Date and time when the client was notified of the worker absence. Null if client_notified is False. Used to measure notification SLA compliance against MSA contractual obligations.',
    `client_notified` BOOLEAN COMMENT 'Indicates whether the client organization has been notified of this worker absence (True) or not (False). Critical for client SLA compliance tracking — unnotified absences may breach MSA notification obligations.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this absence record was first created in the system. Establishes the audit trail start point and is used for data lineage tracking in the Silver layer lakehouse.',
    `documentation_due_date` DATE COMMENT 'Deadline by which the worker must submit required leave documentation. Under FMLA, employers may require documentation within 15 calendar days of the leave request. Drives compliance follow-up workflows.',
    `documentation_received` BOOLEAN COMMENT 'Indicates whether required supporting documentation (e.g., physician certification for FMLA, jury summons, death certificate for bereavement) has been received and verified (True) or is outstanding (False).',
    `fmla_hours_used` DECIMAL(18,2) COMMENT 'Number of hours counted against the workers annual FMLA entitlement (up to 480 hours / 12 weeks per year). Populated only when fmla_qualifying is True. Required for DOL FMLA recordkeeping compliance.',
    `fmla_qualifying` BOOLEAN COMMENT 'Indicates whether this absence qualifies under the Family and Medical Leave Act (FMLA) (True) or not (False). Triggers FMLA tracking, 3-year recordkeeping retention, and DOL compliance workflows.',
    `is_paid` BOOLEAN COMMENT 'Indicates whether the absence is compensated (True) or unpaid (False). Determines payroll treatment: paid absences draw from PTO/sick balances or holiday pay; unpaid absences result in payroll deductions.',
    `is_partial_day` BOOLEAN COMMENT 'Indicates whether the absence covers only part of a scheduled workday (True) rather than full days (False). Partial-day absences require hour-level tracking for accurate payroll deduction and FMLA intermittent leave accounting.',
    `kronos_leave_ref` STRING COMMENT 'Source system identifier for this absence record as assigned by the Kronos Workforce Ready leave management module. Used for data lineage, reconciliation, and integration with the Silver layer from the operational system of record.',
    `leave_reason_code` STRING COMMENT 'Standardized reason code from the Kronos leave management module identifying the specific reason for the absence (e.g., FMLA-SELF, FMLA-FAMILY, PSL-CA, JURY, BRVMT-IMM). Supports regulatory reporting and state-specific paid sick leave law compliance.',
    `pay_period_end_date` DATE COMMENT 'End date of the payroll pay period in which this absence record falls. Combined with pay_period_start_date to define the payroll processing window for this absence.',
    `pay_period_start_date` DATE COMMENT 'Start date of the payroll pay period in which this absence record falls. Used to align absence data with payroll processing cycles in TempWorks Payroll.',
    `payroll_processed` BOOLEAN COMMENT 'Indicates whether this absence record has been included in a completed payroll processing run (True) or is still pending payroll (False). Prevents double-processing and confirms the absence has been reflected in worker compensation.',
    `per_diem_applicable` BOOLEAN COMMENT 'Indicates whether the workers per diem allowance is affected by this absence (True) or not (False). Per diem payments may be suspended or prorated for absent days depending on the assignment contract terms.',
    `pto_balance_before` DECIMAL(18,2) COMMENT 'Workers available PTO balance in hours immediately prior to this absence being applied. Provides a point-in-time snapshot for audit, dispute resolution, and worker self-service reporting.',
    `pto_hours_consumed` DECIMAL(18,2) COMMENT 'Number of accrued Paid Time Off (PTO) hours deducted from the workers PTO balance to cover this absence. Zero for unpaid absences or absences covered by other leave types (e.g., FMLA, holiday pay).',
    `replacement_requested` BOOLEAN COMMENT 'Indicates whether a replacement worker has been requested to cover this absence (True) or not (False). Triggers workforce scheduling and dispatch workflows to source a backfill worker for the client site.',
    `scheduled_hours` DECIMAL(18,2) COMMENT 'Total number of hours the worker was originally scheduled to work during the absence period. Provides the baseline against which absence_hours is measured for partial-day absence tracking.',
    `sla_breach_flag` BOOLEAN COMMENT 'Indicates whether this absence has caused or is at risk of causing a breach of the client SLA (True) — for example, if the absence results in insufficient staffing levels below the contracted headcount threshold. Feeds client SLA compliance reporting.',
    `state_leave_law_code` STRING COMMENT 'Code identifying the applicable state-specific paid sick leave or family leave law governing this absence (e.g., CA-HWHFA for California Healthy Workplaces Healthy Families Act, NY-PFL for New York Paid Family Leave). Ensures compliance with state-level leave mandates beyond federal FMLA.',
    `submitted_timestamp` TIMESTAMP COMMENT 'Date and time when the worker or manager submitted the absence request in Kronos Workforce Ready. Establishes the start of the approval workflow and is used for SLA measurement of approval turnaround time.',
    `termination_trigger` BOOLEAN COMMENT 'Indicates whether this absence has triggered an assignment termination workflow (True) in Bullhorn ATS/CRM. Applicable for contingent workers with unexcused absences that breach the no-call/no-show policy threshold.',
    `unexcused_flag` BOOLEAN COMMENT 'Indicates whether this absence has been classified as unexcused (True) — i.e., the worker did not provide adequate notice or documentation. Unexcused absences for contingent workers may trigger assignment termination workflows per staffing agency policy.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this absence record was last modified. Tracks changes to approval status, documentation receipt, payroll processing, and other lifecycle updates for audit and data quality purposes.',
    CONSTRAINT pk_absence_record PRIMARY KEY(`absence_record_id`)
) COMMENT 'Records worker absences, PTO usage, sick leave, FMLA leave, holiday observances, jury duty, bereavement, and unexcused absences within a pay period. Captures absence type, absence date range, hours absent, PTO balance consumed, leave reason code, approval status, paid/unpaid indicator, client notification flag, and replacement worker request trigger. Sourced from Kronos Workforce Ready leave management module. Feeds payroll deductions, workforce availability reporting, and client SLA compliance tracking. For contingent workers, unexcused absences may trigger assignment termination workflows. Subject to FMLA recordkeeping requirements (3-year retention) and state-specific paid sick leave laws (e.g., California Healthy Workplaces, Healthy Families Act).';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`schedule` (
    `schedule_id` BIGINT COMMENT 'Unique surrogate identifier for the planned work schedule record in the Kronos Workforce Ready scheduling module. Primary key for the schedule data product.',
    `assignment_id` BIGINT COMMENT 'Reference to the contingent worker placement assignment this schedule belongs to. Links the planned schedule to the active placement record in Bullhorn ATS/CRM.',
    `client_account_id` BIGINT COMMENT 'Reference to the client organization at whose worksite the scheduled shift is to be performed. Links to the client master record in Bullhorn ATS/CRM.',
    `contract_rate_schedule_id` BIGINT COMMENT 'Foreign key linking to contract.contract_rate_schedule. Business justification: Shift schedules are built using contracted rate cards; scheduling systems pull bill/pay rates from rate schedules when creating shifts for accurate cost forecasting. Real business process: shift costi',
    `order_header_id` BIGINT COMMENT 'Reference to the job order (requisition) that originated the placement and governs the scheduled work. Links to the job order record in Bullhorn ATS/CRM.',
    `ot_rule_id` BIGINT COMMENT 'Foreign key linking to timesheet.ot_rule. Business justification: schedule currently has ot_rule_type as STRING and ot_threshold_hours as DECIMAL. Should FK to ot_rule.ot_rule_id for authoritative OT calculation rules including daily/weekly thresholds, multipliers, ',
    `profile_id` BIGINT COMMENT 'Reference to the contingent worker whose planned work schedule is defined by this record. Links to the candidate/worker master record in Bullhorn ATS/CRM.',
    `readiness_status_id` BIGINT COMMENT 'Foreign key linking to credentialing.readiness_status. Business justification: Schedules can only be published for workers meeting credential requirements for that assignment/client. Scheduling systems validate readiness_status before confirming shifts. Standard gate in VMS/MSP ',
    `supervisor_id` BIGINT COMMENT 'Reference to the on-site supervisor or manager responsible for overseeing the contingent worker during this scheduled shift. Used for escalation routing, timesheet approval workflows, and client relationship management.',
    `template_id` BIGINT COMMENT 'Reference to the reusable schedule template in Kronos Workforce Ready from which this schedule instance was generated. Enables template-based scheduling for recurring shift patterns and simplifies bulk schedule management.',
    `wage_hour_determination_id` BIGINT COMMENT 'Foreign key linking to compliance.wage_hour_determination. Business justification: Schedule creation must respect wage-hour determinations: OT thresholds, meal break requirements, rest periods, and spread-of-hours rules. Real business process: compliant shift scheduling to avoid vio',
    `work_location_id` BIGINT COMMENT 'Reference to the physical worksite or client facility where the scheduled shift is to be performed. Used for geographic workforce distribution reporting, per diem eligibility determination, and site-level scheduling analytics.',
    `bill_rate` DECIMAL(18,2) COMMENT 'The hourly rate charged to the client for the contingent workers time on this scheduled shift. Used for client invoicing in Salesforce Revenue Cloud and for spread/gross margin calculation. Confidential business financial data.',
    `confirmed_by_worker` BOOLEAN COMMENT 'Indicates whether the contingent worker has acknowledged and confirmed the scheduled shift in Kronos Workforce Ready. Used for workforce readiness tracking and to reduce no-show risk.',
    `cost_center_code` STRING COMMENT 'Client or internal cost center code to which the scheduled labor hours are to be allocated. Used for client billing segmentation, internal labor cost allocation, and financial reporting in Oracle NetSuite ERP.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which this schedule record was first created in the source system (Kronos Workforce Ready). Used for audit trail, data lineage, and schedule lead-time analytics.',
    `day_of_week` STRING COMMENT 'The day of the week on which this shift is scheduled. Used for recurring schedule pattern analysis, weekend/weekday differential pay identification, and workforce scheduling analytics. [ENUM-REF-CANDIDATE: Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday — 7 candidates stripped; promote to reference product]',
    `department_code` STRING COMMENT 'Client department or business unit code associated with the scheduled shift. Used for client-side labor distribution reporting, workforce analytics, and billing breakdown by department.',
    `dt_bill_rate` DECIMAL(18,2) COMMENT 'The hourly rate charged to the client for double-time (DT) hours on this schedule. Used for accurate client invoicing when DT hours are incurred per the applicable rate agreement.',
    `dt_pay_rate` DECIMAL(18,2) COMMENT 'The hourly compensation rate applicable to double-time (DT) hours, typically triggered after a defined threshold of daily or weekly hours (e.g., 12+ hours/day in certain states). Used for payroll processing in TempWorks Payroll.',
    `effective_end_date` DATE COMMENT 'The calendar date on which this schedule definition expires or is superseded. Nullable for open-ended schedules that remain in effect until the assignment end date. Used for schedule versioning and historical comparison.',
    `effective_start_date` DATE COMMENT 'The calendar date from which this schedule definition becomes active and applicable to the workers assignment. Defines the beginning of the schedules validity window. Used for schedule versioning and historical comparison.',
    `expected_weekly_hours` DECIMAL(18,2) COMMENT 'Total planned working hours per week for the worker on this assignment schedule. Used for FTE (Full-Time Equivalent) calculation, OT threshold monitoring, and workforce planning. Typically 40 hours for full-time contingent placements.',
    `is_billable` BOOLEAN COMMENT 'Indicates whether the hours on this scheduled shift are billable to the client. False for internal training shifts, orientation periods, or non-billable administrative time. Drives client invoicing logic in Salesforce Revenue Cloud.',
    `is_holiday` BOOLEAN COMMENT 'Indicates whether this scheduled shift falls on a recognized holiday, which may trigger holiday premium pay rates per the client MSA (Master Service Agreement) or worker contract.',
    `is_per_diem_eligible` BOOLEAN COMMENT 'Indicates whether the contingent worker is eligible to receive per diem allowance for this scheduled shift based on travel distance, assignment location, and IRS tax home rules.',
    `kronos_schedule_ref` STRING COMMENT 'The native schedule record identifier as assigned by the Kronos Workforce Ready source system. Used for cross-system reconciliation, data lineage, and re-ingestion deduplication in the Databricks Silver Layer.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The date and time at which this schedule record was most recently updated in the source system. Used for change detection in incremental data loads, audit trail, and schedule modification tracking.',
    `notes` STRING COMMENT 'Free-text field for operational notes or special instructions associated with this scheduled shift, such as dress code requirements, access badge instructions, or client-specific directives. Not used for structured data.',
    `ot_bill_rate` DECIMAL(18,2) COMMENT 'The hourly rate charged to the client for overtime (OT) hours worked beyond the standard threshold on this schedule. Used for accurate client invoicing when OT hours are incurred.',
    `ot_pay_rate` DECIMAL(18,2) COMMENT 'The hourly compensation rate applicable to overtime (OT) hours worked beyond the standard threshold (typically 40 hours/week or 8 hours/day) on this schedule. Must comply with FLSA overtime premium requirements (minimum 1.5x regular pay rate).',
    `pay_rate` DECIMAL(18,2) COMMENT 'The hourly compensation rate to be paid to the contingent worker for hours worked on this scheduled shift. Used for payroll processing in TempWorks Payroll and for spread/gross margin calculation. Confidential business financial data.',
    `per_diem_rate` DECIMAL(18,2) COMMENT 'Daily allowance amount payable to the contingent worker for meals, lodging, or incidental expenses when the assignment requires travel or work away from the workers tax home. Governed by IRS per diem rules. Null if per diem is not applicable to this schedule.',
    `position_title` STRING COMMENT 'The job title or role designation of the contingent worker for this scheduled shift, as defined in the job order. Used for workforce reporting, skill-based scheduling analytics, and compliance with EEOC job classification requirements.',
    `published_date` DATE COMMENT 'The calendar date on which the schedule was published and made visible to the contingent worker. Used to measure schedule advance notice compliance and worker communication lead time.',
    `schedule_number` STRING COMMENT 'Externally-known business identifier for the schedule record as assigned by Kronos Workforce Ready (e.g., SCH-2024-00123). Used for cross-system reference and operational communication.',
    `schedule_status` STRING COMMENT 'Current lifecycle state of the planned schedule record. Draft indicates the schedule is being built; published indicates it has been released to the worker; confirmed indicates worker acknowledgement; modified indicates a post-publish change; cancelled indicates the shift was removed; completed indicates the shift period has passed.. Valid values are `draft|published|confirmed|modified|cancelled|completed`',
    `scheduled_break_minutes` STRING COMMENT 'Total planned unpaid break duration in minutes for this shift as defined in the schedule template. Used to calculate net scheduled working hours and to validate compliance with mandatory rest period regulations.',
    `scheduled_hours` DECIMAL(18,2) COMMENT 'Total number of planned working hours for this shift, excluding unpaid break time. Represents the expected billable and payable hours for the shift. Used as the baseline for actual vs. scheduled variance reporting and OT threshold monitoring.',
    `shift_date` DATE COMMENT 'The specific calendar date on which this scheduled shift is to occur. Distinct from shift_start_time in that it provides a day-level grain for schedule reporting, calendar views, and daily workforce planning without requiring timestamp precision.',
    `shift_end_time` TIMESTAMP COMMENT 'The planned date and time at which the contingent workers shift is scheduled to end, expressed in local worksite time with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used in conjunction with shift_start_time to derive scheduled shift duration for variance analysis.',
    `shift_start_time` TIMESTAMP COMMENT 'The planned date and time at which the contingent workers shift is scheduled to begin, expressed in local worksite time with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Serves as the baseline for actual time-entry variance analysis and OT calculation.',
    `shift_type` STRING COMMENT 'Classification of the scheduled shift by time-of-day or day-of-week category. Used for differential pay rate application, OT (Overtime) and DT (Double Time) rule triggering, and workforce analytics. [ENUM-REF-CANDIDATE: day|evening|night|weekend|holiday|on_call — promote to reference product if additional shift types are required]. Valid values are `day|evening|night|weekend|holiday|on_call`',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this schedule record was sourced or last updated. Supports data lineage tracking and reconciliation across integrated systems in the Databricks Silver Layer.. Valid values are `KRONOS|BULLHORN|BEELINE|MANUAL`',
    `worker_confirmation_timestamp` TIMESTAMP COMMENT 'The date and time at which the contingent worker confirmed the scheduled shift. Null if the worker has not yet confirmed. Used for advance notice compliance measurement and scheduling analytics.',
    CONSTRAINT pk_schedule PRIMARY KEY(`schedule_id`)
) COMMENT 'Defines the planned work schedule for a contingent worker on a specific assignment, including scheduled shift start/end times, days of week, shift type (day/evening/night/weekend), expected weekly hours, and effective date range. Sourced from Kronos Workforce Ready scheduling module. Serves as the baseline against which actual time entries are compared for variance analysis and OT calculation.';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`shift` (
    `shift_id` BIGINT COMMENT 'Unique system-generated identifier for a specific scheduled or worked shift instance for a contingent worker. Primary key for the shift data product in the Kronos Workforce Ready time and attendance system.',
    `assignment_id` BIGINT COMMENT 'Identifier of the active placement or assignment under which this shift is worked. Links the shift to the specific job order and client engagement governing the workers deployment.',
    `client_account_id` BIGINT COMMENT 'Identifier of the client organization at whose worksite this shift is performed. Used for client-level labor reporting, billing, and SLA compliance tracking.',
    `contract_rate_schedule_id` BIGINT COMMENT 'Foreign key linking to contract.contract_rate_schedule. Business justification: Actual worked shifts must reference the rate schedule used for billing/payroll; variance analysis compares shift rates to contracted rates for margin analysis. Real business process: shift billing rec',
    `order_header_id` BIGINT COMMENT 'Identifier of the job order (requisition) associated with this shift. Connects the shift to the clients staffing request for labor analytics and billing reconciliation.',
    `pay_period_id` BIGINT COMMENT 'Identifier of the payroll pay period to which this shift belongs. Links the shift to the correct payroll processing cycle in TempWorks Payroll for wage calculation and tax filing.',
    `profile_id` BIGINT COMMENT 'Identifier of the contingent worker assigned to this shift. Links to the worker/candidate master record in Bullhorn ATS/CRM and Kronos Workforce Ready.',
    `schedule_id` BIGINT COMMENT 'Foreign key linking to timesheet.schedule. Business justification: shift represents an actual worked shift instance, while schedule represents the planned schedule. A shift should link back to the schedule it was planned under to enable variance analysis (scheduled v',
    `staff_profile_id` BIGINT COMMENT 'Identifier of the supervisor, manager, or client contact who approved this shift. Used for approval audit trail, accountability tracking, and compliance with client MSA approval requirements.',
    `timesheet_id` BIGINT COMMENT 'Identifier of the parent timesheet record that aggregates this shift along with other shifts in the same submission period. Links shift-level data to the timesheet approval workflow.',
    `work_location_id` BIGINT COMMENT 'Identifier of the specific physical worksite or location where the shift is performed. Supports multi-site client operations, workers compensation jurisdiction assignment, and OSHA compliance.',
    `absence_code` STRING COMMENT 'Code indicating the reason for a missed or partial shift absence (e.g., NCNS for no-call-no-show, SICK, FMLA, PTO, JURY). Used for attendance tracking, FMLA compliance, and workforce reliability analytics. [ENUM-REF-CANDIDATE: NCNS|SICK|FMLA|PTO|JURY|BEREAVEMENT|MILITARY — promote to reference product]',
    `actual_end_time` TIMESTAMP COMMENT 'The actual clock-out date and time recorded when the worker ended the shift. Sourced from Kronos punch data. Used for early departure tracking, schedule variance, and payable hours calculation.',
    `actual_start_time` TIMESTAMP COMMENT 'The actual clock-in date and time recorded when the worker began the shift. Sourced from Kronos punch data. Used for tardiness tracking, schedule variance, and payable hours calculation.',
    `approval_status` STRING COMMENT 'Current state of the shift approval workflow. pending = awaiting supervisor review; approved = authorized for payroll and billing; rejected = returned for correction; disputed = worker or client contest; auto_approved = system-approved per configured rules.. Valid values are `pending|approved|rejected|disputed|auto_approved`',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the shift was approved by the authorized approver. Used for SLA tracking on approval turnaround time and payroll cutoff compliance.',
    `billable_hours` DECIMAL(18,2) COMMENT 'Total hours approved for client invoicing for this shift. May differ from worked_hours due to client-specific billing rules, approved adjustments, or non-billable time. Feeds Salesforce Revenue Cloud for invoice generation.',
    `break_minutes` STRING COMMENT 'Total scheduled or actual break time in minutes deducted from the shift duration. Includes meal breaks and rest periods. Used for net hours calculation and compliance with mandatory break laws (e.g., FLSA, state labor codes).',
    `cost_center_code` STRING COMMENT 'Client or internal cost center code to which this shifts labor cost is allocated. Supports client-side cost allocation reporting, internal P&L tracking, and Oracle NetSuite ERP general ledger posting.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this shift record was first created in the system, either by the scheduling engine or manual entry. Serves as the record audit creation timestamp for data lineage and compliance purposes.',
    `department_code` STRING COMMENT 'Client department or business unit code associated with this shift. Used for granular labor cost reporting to clients and workforce analytics by department.',
    `differential_code` STRING COMMENT 'Code identifying the pay differential applicable to this shift based on timing (e.g., evening, night, weekend, holiday). Drives premium pay rate calculations in TempWorks Payroll and corresponding bill rate adjustments. [ENUM-REF-CANDIDATE: DAY|EVE|NIGHT|WEEKEND|HOLIDAY|HAZARD|ONCALL — promote to reference product]',
    `dt_hours` DECIMAL(18,2) COMMENT 'Hours worked beyond the double-time threshold (typically 12 hours/day or 7th consecutive day per California Labor Code and similar state laws) classified as double-time (DT) at 2x pay rate. Used for payroll and client billing at DT bill rate.',
    `geofence_verified` BOOLEAN COMMENT 'Indicates whether the workers clock-in/clock-out was verified within the approved geofence boundary of the worksite. Supports fraud prevention, buddy-punching detection, and client worksite compliance requirements.',
    `is_holiday` BOOLEAN COMMENT 'Indicates whether this shift falls on a recognized company or federal holiday. Drives holiday pay premium calculations in TempWorks Payroll and holiday bill rate surcharges for client invoicing.',
    `is_weekend` BOOLEAN COMMENT 'Indicates whether this shift falls on a Saturday or Sunday. Used to apply weekend shift differential pay codes and corresponding client bill rate adjustments per MSA terms.',
    `job_code` STRING COMMENT 'Standardized job classification code for the role performed during this shift. Drives pay rate lookup, workers compensation classification, and EEOC/OFCCP labor category reporting.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when this shift record was most recently modified. Tracks the latest change for data lineage, audit compliance, and incremental data pipeline processing in the Databricks Silver Layer.',
    `notes` STRING COMMENT 'Free-text field for supervisor or worker notes related to this shift, such as reasons for schedule deviation, special instructions, incident observations, or client-specific comments. Used for operational context and dispute resolution.',
    `ot_hours` DECIMAL(18,2) COMMENT 'Hours worked beyond the standard threshold (typically 40 hours/week or 8 hours/day depending on state law) classified as overtime (OT) at 1.5x pay rate. Critical for FLSA compliance, payroll cost management, and client billing at OT bill rate.',
    `payable_hours` DECIMAL(18,2) COMMENT 'Total hours approved for worker compensation for this shift. May differ from worked_hours due to guaranteed minimum hours, rounding rules, or approved adjustments. Feeds TempWorks Payroll for worker pay calculation.',
    `per_diem_amount` DECIMAL(18,2) COMMENT 'Dollar amount of per diem allowance payable to the worker for this shift. Applicable for travel assignments and remote deployments. Sourced from assignment-level per diem rate configuration. Feeds TempWorks Payroll.',
    `per_diem_eligible` BOOLEAN COMMENT 'Indicates whether the worker is eligible to receive a per diem allowance for this shift (e.g., for travel assignments, remote worksite deployments). Drives per diem payment processing in TempWorks Payroll.',
    `punch_source` STRING COMMENT 'Method or system through which the shifts time punches were captured. time_clock = physical Kronos terminal; mobile_app = Kronos mobile; web_portal = browser entry; supervisor_entry = manager-entered; vms = Beeline VMS submission; manual_adjustment = back-office correction.. Valid values are `time_clock|mobile_app|web_portal|supervisor_entry|vms|manual_adjustment`',
    `regular_hours` DECIMAL(18,2) COMMENT 'Portion of worked hours classified as straight-time regular pay hours, not subject to overtime or double-time premiums. Used for payroll processing and client billing at the standard pay/bill rate.',
    `schedule_variance_minutes` STRING COMMENT 'Difference in minutes between actual worked hours and scheduled hours for this shift (actual minus scheduled). Positive values indicate overtime beyond schedule; negative values indicate early departure or missed time. Key metric for schedule adherence and labor analytics.',
    `scheduled_end_time` TIMESTAMP COMMENT 'The planned end date and time of the shift as defined in the workforce schedule. Used alongside scheduled_start_time to determine planned shift duration and schedule adherence.',
    `scheduled_hours` DECIMAL(18,2) COMMENT 'Total planned hours for the shift as defined in the workforce schedule, calculated from scheduled_start_time to scheduled_end_time minus planned break time. Used for headcount planning and FTE calculations.',
    `scheduled_start_time` TIMESTAMP COMMENT 'The planned start date and time of the shift as defined in the workforce schedule. Used for schedule adherence analysis, variance calculation, and dispatch confirmation.',
    `shift_date` DATE COMMENT 'The calendar date on which the shift is scheduled or was worked. Serves as the principal business event date for the shift, used for daily labor reporting, payroll period alignment, and client billing.',
    `shift_number` STRING COMMENT 'Externally-known business identifier for this shift instance, typically generated by Kronos Workforce Ready. Used for cross-system reference, timesheet reconciliation, and worker/supervisor communication.',
    `shift_status` STRING COMMENT 'Current lifecycle state of the shift. scheduled = future shift confirmed; in_progress = worker clocked in; completed = shift ended and hours recorded; missed = worker did not appear; cancelled = shift removed before start; no_call_no_show = worker absent without notification.. Valid values are `scheduled|in_progress|completed|missed|cancelled|no_call_no_show`',
    `shift_type` STRING COMMENT 'Classification of the shift by its operational nature. regular = standard scheduled shift; overtime = OT-designated shift; holiday = worked on a recognized holiday; on_call = standby/on-call shift; split = non-contiguous shift segments; per_diem = per diem eligible shift.. Valid values are `regular|overtime|holiday|on_call|split|per_diem`',
    `start_variance_minutes` STRING COMMENT 'Difference in minutes between actual_start_time and scheduled_start_time (actual minus scheduled). Positive values indicate tardiness; negative values indicate early arrival. Used for punctuality tracking and SLA compliance.',
    `worked_hours` DECIMAL(18,2) COMMENT 'Total actual hours worked during the shift, calculated from actual_start_time to actual_end_time minus actual break time. Represents the gross worked duration before OT/DT classification. Feeds payroll and client billing.',
    `workers_comp_code` STRING COMMENT 'NCCI or state-specific workers compensation classification code applicable to the work performed during this shift. Determines workers comp insurance premium calculation and is required for accurate burden rate costing.',
    CONSTRAINT pk_shift PRIMARY KEY(`shift_id`)
) COMMENT 'Represents a specific scheduled or worked shift instance for a worker, capturing the shift date, planned start/end, actual start/end, shift duration, break time, net hours, shift differential code, and variance from schedule. Distinct from time_entry in that it represents the shift-level aggregation and schedule comparison, while time_entry captures individual punches. Supports scheduling dispatch and labor analytics.';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`ot_rule` (
    `ot_rule_id` BIGINT COMMENT 'Unique system-generated identifier for the overtime and double-time calculation rule record. Primary key for the ot_rule entity. [ROLE: REFERENCE_LOOKUP — this entity defines enumerated OT/DT calculation rules used as a reference by time entry and payroll processing; exempt from per-role minimums per canonical-attrs-enforced rule.]',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: OT rules implement state-specific compliance requirements (CA daily OT, NY spread-of-hours, etc.). Each OT rule must reference the governing state compliance rule. Real business process: jurisdiction-',
    `superseded_by_rule_ot_rule_id` BIGINT COMMENT 'Reference to the ot_rule_id of the newer rule that replaces this rule when rule_status is superseded. Enables rule version chain tracing for historical timesheet recalculation and compliance audits. Null if this rule has not been superseded.',
    `applicable_law_reference` STRING COMMENT 'Specific statutory or regulatory citation governing this OT rule (e.g., FLSA §207, California Labor Code §510, Nevada Revised Statutes §608.018, Davis-Bacon Act 40 U.S.C. §3141). Used for compliance documentation, legal audit trails, and regulatory reporting to DOL and OFCCP.',
    `applies_to_billable_hours` BOOLEAN COMMENT 'Indicates whether this OT rule governs the classification of billable OT hours for client invoicing purposes (True), in addition to payable hours for worker compensation. When True, OT bill rate multipliers are applied in Salesforce Revenue Cloud for client billing. When False, the rule applies only to payroll (pay side) calculations.',
    `approved_by` STRING COMMENT 'Name or user identifier of the payroll manager, compliance officer, or HR administrator who approved this OT rule configuration for activation. Required for SOC 2 Type II change management controls and FLSA compliance audit trails. Populated when rule_status transitions to active.',
    `approved_date` DATE COMMENT 'Date on which this OT rule configuration was formally approved for activation by the authorized approver. Distinct from effective_date (when the rule starts being applied) and created_timestamp (when the record was created). Supports change management audit trails per SOC 2 Type II.',
    `bill_rate_dt_multiplier` DECIMAL(18,2) COMMENT 'Multiplier applied to the standard bill rate to calculate the DT bill rate charged to the client for double-time hours (e.g., 2.00 means the client is billed at 2x the straight-time bill rate for DT hours). Null if the rule does not include a DT tier or if applies_to_billable_hours is False.',
    `bill_rate_ot_multiplier` DECIMAL(18,2) COMMENT 'Multiplier applied to the standard bill rate to calculate the OT bill rate charged to the client for overtime hours (e.g., 1.50 means the client is billed at 1.5x the straight-time bill rate for OT hours). May differ from the pay-side OT multiplier based on client MSA terms. Null if applies_to_billable_hours is False.',
    `blended_rate_method` STRING COMMENT 'Method used to calculate the regular rate of pay for OT purposes when a worker is on multiple concurrent assignments with different pay rates. weighted_average = FLSA §207(g)(1) weighted average of all rates; highest_rate = FLSA §207(g)(2) highest rate method; primary_assignment = rate of the primary assignment governs; not_applicable = worker is on a single assignment only.. Valid values are `weighted_average|highest_rate|primary_assignment|not_applicable`',
    `break_deduction_applies` BOOLEAN COMMENT 'Indicates whether unpaid meal/rest break deductions are applied before OT threshold calculation under this rule. True = break time is deducted from hours worked before OT is computed; False = all clocked hours count toward OT threshold without break deduction. Affects OT calculation in Kronos Workforce Ready.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this OT rule record was first created in the system (ISO 8601 format with timezone offset). Provides audit trail for rule configuration history and supports SOC 2 Type II compliance logging requirements.',
    `daily_dt_threshold_hours` DECIMAL(18,2) COMMENT 'Number of hours worked in a single workday beyond which double-time (DT) pay is triggered (e.g., 12.00 hours per California Labor Code §510). Hours worked above this threshold are compensated at the DT multiplier rate. Null if the rule does not include a daily DT threshold.',
    `daily_ot_threshold_hours` DECIMAL(18,2) COMMENT 'Number of hours worked in a single workday beyond which daily overtime pay is triggered (e.g., 8.00 hours per California Labor Code §510). Hours worked above this threshold and below the DT threshold are compensated at the OT multiplier. Null if the rule does not apply a daily OT threshold.',
    `dt_multiplier` DECIMAL(18,2) COMMENT 'Pay rate multiplier applied to the workers regular rate of pay for hours classified as double-time (e.g., 2.00 for double-time per California Labor Code §510). Null if the rule does not include a DT tier. Used by TempWorks Payroll for DT wage calculation.',
    `effective_date` DATE COMMENT 'Date on which this OT rule becomes effective and begins to be applied to time entry calculations (inclusive). Used for date-range-based rule selection to ensure the correct rule version is applied to historical and current timesheets. Aligns with FLSA and state law effective dates.',
    `expiration_date` DATE COMMENT 'Date on which this OT rule ceases to be effective (inclusive). Null for open-ended rules with no planned expiration. Used in conjunction with effective_date for date-range-based rule version management. When a rule is superseded, this date is set to the day before the new rules effective_date.',
    `flsa_exemption_category` STRING COMMENT 'Specific FLSA exemption category when flsa_exemption_status is exempt or partial_exempt (e.g., executive, administrative, professional, computer_employee, highly_compensated, 207k_public_safety). Null for non-exempt workers. Required for FLSA compliance documentation and OFCCP audits. [ENUM-REF-CANDIDATE: executive|administrative|professional|computer_employee|highly_compensated|207k_public_safety|outside_sales|seasonal — promote to reference product]',
    `flsa_exemption_status` STRING COMMENT 'FLSA overtime exemption classification applicable under this rule. non_exempt = worker is entitled to OT pay under FLSA; exempt = worker meets FLSA white-collar or other exemption criteria and is not entitled to OT; partial_exempt = specific exemption applies to some but not all OT provisions (e.g., §207(k) for law enforcement/fire). Drives OT eligibility in TempWorks Payroll.. Valid values are `non_exempt|exempt|partial_exempt`',
    `holiday_hours_ot_treatment` STRING COMMENT 'Defines how holiday hours are treated for OT threshold calculation. count_as_worked = holiday pay hours count toward weekly OT threshold; exclude = holiday hours are excluded from OT threshold calculation; premium_separate = holiday premium is calculated separately and does not affect OT threshold. Configured per client MSA or state law.. Valid values are `count_as_worked|exclude|premium_separate`',
    `job_category_scope` STRING COMMENT 'Job category or occupational classification to which this OT rule is restricted (e.g., light_industrial, healthcare_rn, it_professional, clerical, all). Null or all indicates the rule applies across all job categories. Supports differentiated OT rules for prevailing wage or union-covered job categories.',
    `jurisdiction_level` STRING COMMENT 'Level of legal jurisdiction governing this OT rule. federal = applies nationwide under FLSA; state = applies within a specific U.S. state; local = applies within a specific municipality or county; contract = applies per client MSA or SOW terms regardless of geography.. Valid values are `federal|state|local|contract`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this OT rule record was most recently updated (ISO 8601 format with timezone offset). Used to detect configuration changes, trigger downstream recalculation of affected timesheets, and support SOC 2 Type II audit logging.',
    `ot_multiplier` DECIMAL(18,2) COMMENT 'Pay rate multiplier applied to the workers regular rate of pay for hours classified as overtime (e.g., 1.50 for time-and-a-half per FLSA §207). Used by TempWorks Payroll to calculate OT wages and by Salesforce Revenue Cloud to calculate OT bill amounts.',
    `prevailing_wage_applies` BOOLEAN COMMENT 'Indicates whether this OT rule incorporates prevailing wage requirements under the Davis-Bacon Act (for federal construction contracts) or the Service Contract Act (SCA) for government service contracts. True = prevailing wage OT rates apply; False = standard commercial OT rates apply. Critical for government staffing contract compliance.',
    `prevailing_wage_determination_number` STRING COMMENT 'DOL wage determination number associated with the prevailing wage schedule governing this OT rule (e.g., WD 2023-0001). Populated only when prevailing_wage_applies is True. Required for Davis-Bacon Act and SCA compliance documentation on government staffing contracts.',
    `pto_counts_toward_ot` BOOLEAN COMMENT 'Indicates whether paid time off (PTO) hours are included in the weekly hours count for OT threshold purposes. True = PTO hours count toward the OT threshold (e.g., 32 hours worked + 8 PTO = 40 hours, no OT triggered); False = only actual hours worked count toward OT threshold per FLSA standard. Configurable per client MSA.',
    `rule_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this OT/DT rule for reference in payroll configurations, VMS integrations, and client billing systems (e.g., FLSA_FED_STD, CA_510_DAILY, DAVIS_BACON_GOV). Used as the business key in Kronos Workforce Ready and TempWorks Payroll rule tables.. Valid values are `^[A-Z0-9_]{2,30}$`',
    `rule_description` STRING COMMENT 'Detailed narrative description of the overtime rule, including the legal basis, applicable thresholds, and any special conditions (e.g., seventh-consecutive-day provisions, blended rate requirements, prevailing wage applicability). Supports compliance documentation and auditor review.',
    `rule_name` STRING COMMENT 'Human-readable name describing the overtime rule (e.g., Federal FLSA Standard 40-Hour Weekly OT, California Daily OT 8/12 Rule, Davis-Bacon Prevailing Wage OT). Used in payroll configuration UIs, compliance reports, and worker assignment documentation.',
    `rule_priority` STRING COMMENT 'Numeric priority rank used for conflict resolution when multiple OT rules are applicable to the same time entry (e.g., a worker in California on a government contract may have federal FLSA, California state, and Davis-Bacon rules all applicable). Lower integer = higher priority. Ensures deterministic OT rule selection in Kronos Workforce Ready and TempWorks Payroll.',
    `rule_status` STRING COMMENT 'Current lifecycle status of the OT rule record. active = currently applied to time entry calculations; inactive = disabled and not applied; draft = under review before activation; superseded = replaced by a newer rule version but retained for historical reference.. Valid values are `active|inactive|draft|superseded`',
    `rule_type` STRING COMMENT 'Classification of the overtime rule by its governing authority or applicability scope. federal = FLSA-based federal standard; state = state-specific labor law (e.g., California, Nevada); client_specific = client-negotiated OT terms in MSA; prevailing_wage = Davis-Bacon Act or SCA government contract rules; blended = multi-assignment blended rate OT calculation.. Valid values are `federal|state|client_specific|prevailing_wage|blended`',
    `seventh_day_dt_threshold_hours` DECIMAL(18,2) COMMENT 'On the seventh consecutive workday, the number of hours beyond which double-time pay applies (e.g., 8.00 hours per California Labor Code §510 — first 8 hours at OT, beyond 8 at DT). Null if seventh_day_ot_applies is False or if no DT tier applies on the seventh day.',
    `seventh_day_ot_applies` BOOLEAN COMMENT 'Indicates whether this rule includes the seventh-consecutive-day OT provision, where all hours worked on the seventh consecutive day of a workweek are paid at OT rate (True) per California Labor Code §510. False for rules that do not include this provision.',
    `source_system` STRING COMMENT 'Operational system of record from which this OT rule configuration was sourced or is mastered. kronos = Kronos Workforce Ready time and attendance; tempworks = TempWorks Payroll rule configuration; beeline = Beeline VMS rate and rule management; manual = manually entered by payroll or compliance team; bullhorn = Bullhorn ATS/CRM placement configuration.. Valid values are `kronos|tempworks|beeline|manual|bullhorn`',
    `source_system_rule_ref` STRING COMMENT 'Native identifier of this OT rule in the originating operational system (e.g., Kronos Workforce Ready pay rule ID, TempWorks Payroll OT rule code). Enables reconciliation between the lakehouse silver layer and the source system for audit and troubleshooting purposes.',
    `state_code` STRING COMMENT 'Two-letter U.S. state abbreviation (ISO 3166-2:US) identifying the state whose labor law governs this OT rule (e.g., CA for California Labor Code §510, NV for Nevada daily OT). Null for federal-level rules applicable nationwide. Used for multi-state OT rule resolution in Kronos Workforce Ready.. Valid values are `^[A-Z]{2}$`',
    `union_agreement_applies` BOOLEAN COMMENT 'Indicates whether this OT rule is governed by or must comply with a collective bargaining agreement (CBA) or union contract. True = union OT provisions apply and may override standard FLSA or state rules; False = no union agreement governs this rule. Relevant for unionized light industrial and healthcare staffing placements.',
    `union_agreement_reference` STRING COMMENT 'Identifier or name of the collective bargaining agreement (CBA) that governs this OT rule when union_agreement_applies is True (e.g., SEIU Local 1199 CBA 2023-2026, Teamsters Local 25 CBA). Null when union_agreement_applies is False. Used for compliance documentation and payroll audit.',
    `weekly_dt_threshold_hours` DECIMAL(18,2) COMMENT 'Number of hours worked in a workweek beyond which double-time pay is triggered (e.g., some state or client rules apply DT after 60 hours/week). Null if the rule does not apply a weekly DT threshold. Distinct from the daily DT threshold.',
    `weekly_ot_threshold_hours` DECIMAL(18,2) COMMENT 'Number of hours worked in a workweek beyond which overtime pay is triggered (e.g., 40.00 hours per FLSA §207 federal standard). Hours worked above this threshold are compensated at the OT multiplier rate. Null if the rule does not apply a weekly OT threshold.',
    `worker_classification_scope` STRING COMMENT 'Worker tax classification to which this OT rule applies. w2_employee = applies only to W-2 employees on payroll; 1099_ic = applies to independent contractors (IC) per contract terms; all = applies regardless of worker classification. Aligns with IRS worker classification rules and FLSA co-employment considerations.. Valid values are `w2_employee|1099_ic|all`',
    `workweek_start_day` STRING COMMENT 'The designated first day of the workweek for purposes of weekly OT threshold calculation (e.g., sunday for a Sunday–Saturday workweek per FLSA §207). Workweek definition is fixed and regularly recurring per FLSA. Configured in Kronos Workforce Ready per client or assignment. [ENUM-REF-CANDIDATE: sunday|monday|tuesday|wednesday|thursday|friday|saturday — 7 candidates stripped; promote to reference product]',
    CONSTRAINT pk_ot_rule PRIMARY KEY(`ot_rule_id`)
) COMMENT 'Reference entity defining overtime and double-time calculation rules applicable to specific clients, states, job categories, or worker classifications. Captures the weekly OT threshold (e.g., 40 hrs/week federal FLSA §207), daily OT threshold (e.g., 8 hrs/day California Labor Code §510), DT threshold (e.g., 12 hrs/day California), seventh-consecutive-day rules, applicable FLSA exemption status, state-specific OT law references, effective date range, and rule priority for conflict resolution. Supports blended OT rate calculation for workers on multiple assignments. Includes prevailing wage OT rules for Davis-Bacon Act compliance on government staffing contracts. Ensures compliant OT/DT classification across all time entries in multi-state staffing operations.';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`pay_period` (
    `pay_period_id` BIGINT COMMENT 'Unique surrogate identifier for each pay period record in the staffing operation. Primary key for the timesheet_pay_period reference entity. [_canonical_skip_reason: REFERENCE_LOOKUP — this entity is a calendar/reference table defining pay period cycles; per-role minimums do not apply, but comprehensive coverage is still provided for operational completeness.]',
    `applicable_states` STRING COMMENT 'Comma-separated list of U.S. state codes (e.g., CA,NY,TX) for which this pay period definition applies. Critical for multi-state staffing operations where state-specific payroll laws (e.g., California daily OT, New York wage payment frequency) require different pay period configurations. Supports SUTA and state tax compliance.',
    `approval_deadline` TIMESTAMP COMMENT 'Precise timestamp by which client supervisors or staffing coordinators must approve submitted timesheets. Drives SLA enforcement for approval workflows and escalation triggers in Kronos Workforce Ready. Supports on-time payroll processing and client billing cycle alignment.',
    `billing_cycle_date` DATE COMMENT 'The date on which client invoices are generated for billable hours worked during this pay period. May differ from check_date in cases where billing and payroll cycles are offset. Feeds Salesforce Revenue Cloud invoice generation and Oracle NetSuite Accounts Receivable.',
    `calendar_year` STRING COMMENT 'The standard calendar year (4-digit integer, e.g., 2024) to which this pay period belongs. Distinct from fiscal_year when the business operates on a non-calendar fiscal year. Used for W-2 and 1099 tax year alignment in TempWorks Payroll.',
    `check_date` DATE COMMENT 'The date on which worker paychecks or direct deposit payments are issued for this pay period. Represents the actual pay date visible on W-2 wage statements and worker pay stubs. Used for tax reporting, FICA, FUTA, and SUTA liability calculations in TempWorks Payroll.',
    `client_segment` STRING COMMENT 'Business segment or client grouping for which this pay period definition is applicable (e.g., Healthcare, Light Industrial, IT Staffing, All). Supports multi-client staffing operations where different client verticals may operate on different pay cycles per MSA (Master Service Agreement) terms.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this pay period record was first created in the data platform. Used for audit trail, data lineage, and SOC 2 Type II compliance. Populated automatically at record insertion and never updated.',
    `dt_threshold_hours` DECIMAL(18,2) COMMENT 'Number of hours worked beyond which double-time (DT) pay rates apply for this pay period. Applicable in states such as California where DT is mandated after 12 hours in a workday or on the 7th consecutive workday. Supports multi-state payroll compliance in TempWorks Payroll.',
    `effective_from` DATE COMMENT 'The date from which this pay period definition record became effective in the system. Supports slowly changing dimension (SCD) tracking for pay period calendar changes (e.g., a client switching from weekly to bi-weekly pay cycles). Enables historical payroll reprocessing and audit compliance.',
    `effective_until` DATE COMMENT 'The date on which this pay period definition record ceases to be effective. Null indicates the record is currently active with no planned end date. Supports SCD Type 2 history tracking for pay period calendar changes and enables point-in-time payroll audit queries.',
    `end_date` DATE COMMENT 'The last calendar date of the pay period. All timesheet hours submitted with a work date on or before this date are grouped into this pay period. Together with start_date, defines the authoritative time boundary for worker compensation and client billing.',
    `fiscal_month` STRING COMMENT 'The fiscal month (1–12) within the fiscal year to which this pay period belongs. Supports monthly financial close processes in Oracle NetSuite ERP and monthly workforce analytics reporting in Power BI Analytics Platform.',
    `fiscal_quarter` STRING COMMENT 'The fiscal quarter (1–4) within the fiscal year to which this pay period belongs. Used for quarterly payroll tax filings (941, SUTA), financial reporting, and KPI dashboards in Power BI Analytics Platform.',
    `fiscal_week_number` STRING COMMENT 'The sequential fiscal week number (1–53) within the fiscal year. Used for weekly labor analytics, overtime threshold tracking, and workforce scheduling reports in Kronos Workforce Ready and Power BI Analytics Platform. Particularly important for weekly pay period types.',
    `fiscal_year` STRING COMMENT 'The fiscal year (4-digit integer, e.g., 2024) to which this pay period belongs. Used for financial reporting, budget allocation, and year-end tax filings in Oracle NetSuite ERP. Supports multi-year analytics in Power BI Analytics Platform.',
    `holiday_adjustment_flag` BOOLEAN COMMENT 'Indicates whether this pay period contains one or more observed holidays that affect standard workday counts, holiday pay eligibility, or payroll processing schedules. When True, payroll coordinators must review holiday pay rules and adjusted cutoff dates. Sourced from Kronos Workforce Ready holiday calendar.',
    `holiday_count` STRING COMMENT 'Number of observed holidays falling within this pay period. Used to calculate adjusted workday counts, holiday pay liability, and per diem adjustments. Supports holiday pay eligibility rules for temporary workers under client MSA (Master Service Agreement) terms.',
    `is_active` BOOLEAN COMMENT 'Indicates whether this pay period record is currently active and available for timesheet assignment and payroll processing. False records represent historical, future-dated, or deactivated periods. Used to filter active periods in Kronos Workforce Ready scheduling and TempWorks Payroll run selection.',
    `is_current_period` BOOLEAN COMMENT 'Indicates whether this is the currently active pay period (i.e., todays date falls within start_date and end_date). Only one record per period_type should have this flag set to True at any given time. Used as a quick filter in operational dashboards and payroll processing queues.',
    `notes` STRING COMMENT 'Free-text field for payroll coordinators to document special instructions, exceptions, or contextual information for this pay period (e.g., Adjusted cutoff due to Thanksgiving holiday, Early check date for Christmas week). Supports operational communication and audit documentation.',
    `ot_threshold_hours` DECIMAL(18,2) COMMENT 'Number of hours worked beyond which overtime (OT) pay rates apply for this pay period. Typically 40.00 hours for weekly FLSA overtime, but may vary by state law (e.g., California daily OT at 8 hours). Critical for payroll compliance and accurate OT cost calculations in TempWorks Payroll.',
    `payroll_cutoff_date` DATE COMMENT 'The deadline by which all timesheets must be submitted and approved for inclusion in this pay periods payroll run. Timesheets received after this date are held for the next pay period or processed as off-cycle adjustments. Operationally critical for TempWorks Payroll batch processing.',
    `payroll_provider_code` STRING COMMENT 'Code identifying the payroll processing provider or entity responsible for executing payroll for this pay period (e.g., TEMPWORKS, EOR_PARTNER_01). Relevant for EOR (Employer of Record) arrangements where a third-party provider processes payroll on behalf of the staffing firm.',
    `payroll_run_type` STRING COMMENT 'Classifies the type of payroll run associated with this pay period. regular = standard scheduled payroll; off_cycle = unscheduled run for missed payments or terminations; supplemental = bonus or commission payments; correction = retroactive adjustment for prior period errors. Drives payroll processing logic in TempWorks Payroll.. Valid values are `regular|off_cycle|supplemental|correction`',
    `per_diem_period_flag` BOOLEAN COMMENT 'Indicates whether per diem allowances are applicable and tracked within this pay period. When True, per diem expense records are expected to be submitted alongside timesheets. Relevant for travel-intensive placements (e.g., healthcare travel nurses, field technicians) where IRS per diem rates apply.',
    `period_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this pay period across systems (e.g., PP-2024-01-001). Used for cross-system reconciliation between Kronos Workforce Ready, TempWorks Payroll, and Salesforce Revenue Cloud billing cycles.. Valid values are `^PP-[0-9]{4}-[0-9]{2}-[0-9]{3}$`',
    `period_name` STRING COMMENT 'Human-readable label for the pay period (e.g., Week 1 Jan 2024, Bi-Weekly Period 3 - Q1 2024). Used in payroll reports, worker pay stubs, and client billing statements for clear period identification.',
    `period_sequence_number` STRING COMMENT 'Sequential ordinal number of this pay period within its fiscal year and period type (e.g., 1st bi-weekly period = 1, 2nd = 2). Used for period-over-period comparison analytics, payroll run ordering, and audit trail sequencing.',
    `period_status` STRING COMMENT 'Current lifecycle status of the pay period. open = timesheets can be submitted; processing = payroll run in progress; locked = no further timesheet changes permitted; closed = payroll finalized and disbursed; cancelled = period voided (rare, e.g., system error). Drives workflow gating in TempWorks Payroll and Kronos Workforce Ready.. Valid values are `open|closed|processing|locked|cancelled`',
    `period_type` STRING COMMENT 'Classification of the pay period cycle frequency. Weekly = 52 periods/year; bi_weekly = 26 periods/year; semi_monthly = 24 periods/year; monthly = 12 periods/year. Critical for multi-client operations where different clients may operate on different pay cycles. Drives payroll run scheduling in TempWorks Payroll.. Valid values are `weekly|bi_weekly|semi_monthly|monthly`',
    `pto_accrual_period_flag` BOOLEAN COMMENT 'Indicates whether PTO (Paid Time Off) accruals are calculated and posted during this pay period. Some staffing arrangements accrue PTO on a per-pay-period basis per state law (e.g., California AB 1522, New York Paid Sick Leave). Drives PTO accrual batch processing in TempWorks Payroll and SAP SuccessFactors.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this pay period definition originated. Kronos Workforce Ready is the primary source for time and attendance pay period calendars; TempWorks Payroll for payroll-specific period definitions; Beeline VMS for contingent workforce program pay cycles. Supports data lineage and reconciliation.. Valid values are `kronos|tempworks|manual|beeline|bullhorn`',
    `source_system_period_ref` STRING COMMENT 'The native identifier of this pay period record in the originating source system (e.g., Kronos pay period ID, TempWorks period key). Used for cross-system reconciliation, data lineage tracing, and integration audit trails between the lakehouse silver layer and operational systems.',
    `standard_hours` DECIMAL(18,2) COMMENT 'Expected number of standard straight-time hours for a full-time worker during this pay period (e.g., 40.00 for a weekly period, 80.00 for bi-weekly). Used as the baseline for overtime (OT) threshold calculations, FTE normalization, and payroll burden rate computations.',
    `start_date` DATE COMMENT 'The first calendar date of the pay period. All timesheet hours submitted with a work date on or after this date are grouped into this pay period. Authoritative boundary for timesheet aggregation and payroll processing.',
    `tax_year` STRING COMMENT 'The IRS tax year (4-digit integer) to which payroll taxes for this period are reported. Typically matches calendar_year but may differ for periods spanning year-end (e.g., a bi-weekly period starting Dec 28 and ending Jan 10). Critical for W-2, 1099, FICA, FUTA, and SUTA tax filing accuracy.',
    `timesheet_submission_deadline` TIMESTAMP COMMENT 'Precise timestamp by which contingent workers must submit their timesheets for the pay period. Includes time-of-day precision to support automated reminder workflows in Kronos Workforce Ready and Bullhorn ATS/CRM. Distinct from payroll_cutoff_date which governs the payroll processing batch.',
    `total_calendar_days` STRING COMMENT 'Total number of calendar days in this pay period (end_date minus start_date plus 1). Used for pro-ration calculations for partial-period placements, per diem allowance calculations, and FTE (Full-Time Equivalent) normalization in workforce analytics.',
    `total_workdays` STRING COMMENT 'Number of standard business workdays (Monday–Friday, excluding holidays) within this pay period. Used for expected hours calculations, attendance rate reporting, and workforce scheduling in Kronos Workforce Ready. Supports SLA (Service Level Agreement) headcount compliance reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this pay period record in the data platform. Used for change tracking, incremental data pipeline processing, and audit compliance. Updated automatically on every record modification.',
    `vms_program_flag` BOOLEAN COMMENT 'Indicates whether this pay period is associated with a VMS (Vendor Management System) managed contingent workforce program (e.g., Beeline VMS). VMS programs may have distinct pay period calendars, approval workflows, and billing cycle alignment requirements separate from direct-client placements.',
    `year_end_period_flag` BOOLEAN COMMENT 'Indicates whether this pay period spans or falls at the calendar year-end boundary (e.g., a bi-weekly period crossing December 31 into January). When True, special year-end payroll processing rules apply including W-2 cutoff handling, FICA wage base reset, and FUTA/SUTA annual limit resets in TempWorks Payroll.',
    CONSTRAINT pk_pay_period PRIMARY KEY(`pay_period_id`)
) COMMENT 'Reference entity defining pay period cycles used across the staffing operation. Captures pay period type (weekly, bi-weekly, semi-monthly, monthly), period start date, period end date, payroll processing cutoff date, check date, fiscal week number, holiday adjustment flag, and active status. Serves as the authoritative calendar for timesheet grouping, payroll runs, and billing cycle alignment. Critical for multi-state operations where different clients may operate on different pay cycles.';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`approved_hours_summary` (
    `approved_hours_summary_id` BIGINT COMMENT 'Primary key for approved_hours_summary',
    `assignment_id` BIGINT COMMENT 'Reference to the active placement or assignment under which the worker performed the hours captured in this summary. Ties the hours to a specific job order and client engagement.',
    `client_account_id` BIGINT COMMENT 'Reference to the client (end-customer) for whom the worker performed services during this pay period. Used to route billable amounts to the correct client invoice.',
    `contract_rate_schedule_id` BIGINT COMMENT 'Foreign key linking to contract.contract_rate_schedule. Business justification: Approved hours summaries aggregate billing using rate schedules; invoicing systems pull contracted rates for billing calculations and client invoice generation. Real business process: invoice generati',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Approved hours are the basis for cost center charge-backs and client invoicing. Staffing firms use summary-level cost center data for management reporting and client billing reconciliation; core to fi',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Approved hours summaries drive batch GL postings for payroll accrual and revenue recognition. The bridge between operational timesheet data and financial accounting; required for automated period-end ',
    `order_header_id` BIGINT COMMENT 'Reference to the job order or requisition (Req) that originated the workers assignment. Enables traceability from approved hours back to the originating staffing request.',
    `pay_period_id` BIGINT COMMENT 'Reference to the pay period calendar record that defines the start and end dates of the period covered by this approved hours summary.',
    `pay_stub_id` BIGINT COMMENT 'Foreign key linking to payroll.pay_stub. Business justification: Approved hours summaries feed directly into pay stub generation. This link enables reconciliation between approved billable hours and actual payment, critical for payroll audit, variance analysis, and',
    `placement_compliance_check_id` BIGINT COMMENT 'Foreign key linking to compliance.placement_compliance_check. Business justification: Hours cannot be approved for billing/payroll until placement passes all compliance checks (I-9, BGC, credentials, safety training). Real business process: compliant billing gate preventing payment for',
    `profile_id` BIGINT COMMENT 'Reference to the contingent worker whose approved hours are summarized in this record. Links to the worker master record in the Candidate/Worker domain.',
    `staff_profile_id` BIGINT COMMENT 'Reference to the individual (typically the client supervisor or staffing coordinator) who formally approved the timesheet hours for this pay period.',
    `timesheet_id` BIGINT COMMENT 'Reference to the source timesheet record from which this approved hours summary was derived. Provides traceability back to the raw time entry data in Kronos Workforce Ready.',
    `amendment_reason` STRING COMMENT 'Free-text description of the reason for any post-approval amendment to this hours summary. Required when is_amended is True. Supports audit trail and dispute resolution.',
    `approval_status` STRING COMMENT 'Current lifecycle state of the approved hours summary record within the timesheet approval workflow. approved indicates hours are cleared for billing and payroll; disputed indicates a client or worker challenge is open; amended indicates a post-approval correction was applied.. Valid values are `pending|approved|rejected|disputed|voided|amended`',
    `approval_timestamp` TIMESTAMP COMMENT 'The exact date and time when the timesheet hours were formally approved by the authorized approver. Represents the principal business event timestamp that triggers downstream billing and payroll processing.',
    `bill_rate` DECIMAL(18,2) COMMENT 'The hourly rate charged to the client for the workers regular hours during this pay period, as defined in the client MSA or VMS rate card. Expressed in USD per hour. Used to calculate total billable amount.',
    `billing_transmission_status` STRING COMMENT 'Indicates the current state of this approved hours summarys transmission to the client billing system (Salesforce Revenue Cloud). invoiced means a client invoice has been generated from this record.. Valid values are `not_transmitted|transmitted|invoiced|failed|reprocessing`',
    `burden_rate_pct` DECIMAL(18,2) COMMENT 'The total employer burden rate applied to this workers payable wages for the pay period, expressed as a decimal percentage. Encompasses FICA, FUTA, SUTA, Workers Compensation (Workers Comp), and benefits costs. Used to calculate fully-loaded labor cost.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this approved hours summary record was first created in the Silver Layer. Supports audit trail and data lineage requirements.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts in this record (e.g., USD, CAD, GBP). Supports multi-currency operations for international staffing engagements.. Valid values are `^[A-Z]{3}$`',
    `dt_bill_rate` DECIMAL(18,2) COMMENT 'The hourly rate charged to the client for double-time (DT) hours during this pay period. Typically 2x the regular bill rate per the client MSA or applicable state labor law.',
    `dt_hours` DECIMAL(18,2) COMMENT 'Total approved double-time (DT) hours worked during the pay period, applicable in jurisdictions or client agreements requiring 2x pay for hours beyond a daily or weekly threshold (e.g., California daily OT rules).',
    `flsa_exemption_status` STRING COMMENT 'Indicates whether the worker is classified as exempt or non-exempt under the Fair Labor Standards Act (FLSA) for this assignment. Non-exempt workers are entitled to overtime pay at 1.5x for hours exceeding 40 per week.. Valid values are `exempt|non_exempt`',
    `gross_margin_amount` DECIMAL(18,2) COMMENT 'The gross margin (Spread) for this pay period, calculated as total_billable_amount minus total_payable_amount minus burden costs. Represents the staffing agencys gross profit contribution from this worker-assignment combination before SG&A.',
    `holiday_hours` DECIMAL(18,2) COMMENT 'Total approved hours worked on designated company or client holidays during the pay period. Holiday hours may carry a premium bill rate and pay rate per the client MSA or worker agreement.',
    `is_amended` BOOLEAN COMMENT 'Indicates whether this approved hours summary record has been amended after initial approval (e.g., due to a timesheet correction, missed punch adjustment, or retroactive rate change). True triggers a reconciliation process in payroll and billing.',
    `is_approved` BOOLEAN COMMENT 'Boolean flag confirming that all hours in this summary have been formally approved by an authorized approver. True indicates the record is cleared for payroll and billing handoff. False indicates approval is still pending or was revoked.',
    `ot_bill_rate` DECIMAL(18,2) COMMENT 'The hourly rate charged to the client for overtime (OT) hours during this pay period. Typically 1.5x the regular bill rate, but may be negotiated differently in the client MSA.',
    `ot_hours` DECIMAL(18,2) COMMENT 'Total approved overtime (OT) hours worked during the pay period, typically hours exceeding 40 per week for non-exempt workers under FLSA. Billed and paid at the OT multiplier rate (commonly 1.5x).',
    `pay_period_end_date` DATE COMMENT 'The last calendar date of the pay period covered by this approved hours summary. Defines the inclusive end boundary for all hours aggregated in this record.',
    `pay_period_start_date` DATE COMMENT 'The first calendar date of the pay period covered by this approved hours summary. Defines the inclusive start boundary for all hours aggregated in this record.',
    `pay_rate` DECIMAL(18,2) COMMENT 'The hourly rate paid to the worker for regular hours during this pay period, as defined in the workers placement agreement. Expressed in USD per hour. Used to calculate total payable amount and gross margin (Spread).',
    `payroll_transmission_status` STRING COMMENT 'Indicates the current state of this approved hours summarys transmission to the payroll processing system (TempWorks Payroll). confirmed means payroll has acknowledged receipt and the record is locked for the pay run.. Valid values are `not_transmitted|transmitted|confirmed|failed|reprocessing`',
    `per_diem_rate` DECIMAL(18,2) COMMENT 'The daily per diem allowance rate paid to the worker per approved per diem unit. Must not exceed IRS-published per diem limits to maintain tax-free treatment. Expressed in USD per day.',
    `per_diem_units` DECIMAL(18,2) COMMENT 'Number of per diem units (typically days) approved for the worker during the pay period. Per diem is a daily allowance paid to workers for meals, lodging, or incidentals when working away from their tax home. Not subject to payroll taxes when within IRS limits.',
    `pto_hours` DECIMAL(18,2) COMMENT 'Total approved paid time off (PTO) hours for the worker during the pay period. PTO hours are payable to the worker but are typically not billable to the client unless specified in the MSA.',
    `regular_hours` DECIMAL(18,2) COMMENT 'Total approved regular (straight-time) hours worked by the worker during the pay period, excluding overtime and double-time. Used as the base quantity for both client billing and worker payroll at the standard bill rate and pay rate respectively.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this approved hours summary was sourced or triggered. Kronos Workforce Ready is the primary source; Beeline VMS may be the source for MSP-managed programs; Manual indicates a staffing coordinator override entry.. Valid values are `Kronos|Beeline|Bullhorn|Manual`',
    `summary_number` STRING COMMENT 'Externally-visible business identifier for this approved hours summary record, formatted as AHS-{YYYY}-{WW}-{SEQUENCE}. Used in billing and payroll correspondence to reference a specific approved period.. Valid values are `^AHS-[0-9]{4}-[0-9]{2}-[0-9]{6}$`',
    `total_billable_amount` DECIMAL(18,2) COMMENT 'Total gross amount to be invoiced to the client for this pay period, calculated as the sum of (regular_hours × bill_rate) + (ot_hours × ot_bill_rate) + (dt_hours × dt_bill_rate) + (holiday_hours × applicable holiday bill rate). Feeds Salesforce Revenue Cloud invoice generation.',
    `total_hours` DECIMAL(18,2) COMMENT 'Sum of all approved hour types (regular + OT + DT + holiday) for the worker during the pay period. Represents the total time-based quantity used for workforce analytics and FTE calculations. Excludes PTO hours.',
    `total_payable_amount` DECIMAL(18,2) COMMENT 'Total gross wages payable to the worker for this pay period, calculated as the sum of (regular_hours × pay_rate) + (ot_hours × ot_pay_rate) + (dt_hours × dt_pay_rate) + (holiday_hours × holiday pay rate) + (per_diem_units × per_diem_rate). Feeds TempWorks Payroll processing.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this approved hours summary record was last modified. Tracks amendments such as retroactive adjustments or correction reprocessing.',
    `vms_requisition_number` STRING COMMENT 'The requisition or purchase order number assigned by the clients Vendor Management System (VMS), such as Beeline, for this workers engagement. Required on client invoices for MSP-managed programs.',
    `work_location_type` STRING COMMENT 'Indicates whether the worker performed services on-site at the client location, fully remote, or in a hybrid arrangement during this pay period. Affects per diem eligibility and certain state tax obligations.. Valid values are `onsite|remote|hybrid`',
    `worker_type` STRING COMMENT 'Classification of the workers tax and employment relationship for this assignment. W-2 indicates a staffing agency employee; 1099 indicates an independent contractor (IC); C2C indicates a corp-to-corp engagement. Drives payroll tax treatment and burden rate application.. Valid values are `W2|1099|C2C`',
    `workers_comp_code` STRING COMMENT 'The National Council on Compensation Insurance (NCCI) workers compensation class code assigned to the worker for this assignment. Determines the workers comp insurance premium rate applied within the burden rate calculation.',
    CONSTRAINT pk_approved_hours_summary PRIMARY KEY(`approved_hours_summary_id`)
) COMMENT 'Unified aggregated summary of approved hours for a worker-assignment-client combination within a pay period, broken down by pay type (regular, OT, DT, per diem, holiday). Serves as the single authoritative handoff record for both client invoice generation (billing domain) and payroll processing (payroll domain). Captures total regular hours, OT hours, DT hours, per diem units, bill rate applied, pay rate applied, total billable amount, total payable amount, burden rate components, approval confirmation flag, and payroll transmission status. Replaces separate billable and payable hour summaries to ensure a single reconciled SSOT. Distinct from raw time_entry records — this is the approved, billing-and-payroll-ready output of the timesheet approval process.';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`per_diem_claim` (
    `per_diem_claim_id` BIGINT COMMENT 'Unique system-generated identifier for each per diem allowance claim record submitted by a contingent worker. Serves as the primary key for this entity.',
    `assignment_id` BIGINT COMMENT 'Reference to the specific placement or assignment for which the per diem claim is being submitted. Ties the claim to a client engagement, job order, and work location for billing and compliance purposes.',
    `client_account_id` BIGINT COMMENT 'Reference to the client (end customer) associated with the assignment for which the per diem is claimed. Used to determine client-billable per diem charges and to apply client-specific per diem rate agreements.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Per diem costs are allocated to cost centers for client reimbursement and project costing. Travel-intensive staffing engagements require cost center tracking of per diem for accurate client billing an',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Per diem expenses post to specific GL accounts (travel/expense accounts) for financial reporting and tax compliance. Staffing firms must track per diem separately from wages for IRS reporting and clie',
    `invoice_id` BIGINT COMMENT 'Reference to the client invoice in Salesforce Revenue Cloud to which this per diem charge has been applied. Populated once the claim is approved and included in a billing cycle. Null if not yet billed or not client-billable.',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: Per diem rates vary by work location; IRS compliance and client billing require linking claims to specific client sites. Essential for GSA locality-based per diem rate determination and client site-sp',
    `pay_period_id` BIGINT COMMENT 'Reference to the payroll pay period in which this per diem reimbursement will be or was processed. Links the claim to the TempWorks Payroll pay cycle for non-taxable reimbursement disbursement.',
    `profile_id` BIGINT COMMENT 'Reference to the contingent worker (candidate/associate) who submitted this per diem claim. Links to the worker/candidate master record in Bullhorn ATS/CRM and TempWorks Payroll.',
    `staff_profile_id` BIGINT COMMENT 'Reference to the internal staff member or manager who approved or rejected the per diem claim. Supports approval audit trail, delegation-of-authority compliance, and workflow accountability.',
    `timesheet_id` BIGINT COMMENT 'Reference to the timesheet record for the corresponding work period during which the per diem expense was incurred. Links per diem claims to the authoritative hours record in Kronos Workforce Ready for payroll and billing reconciliation.',
    `approval_timestamp` TIMESTAMP COMMENT 'The date and time when the per diem claim was approved or rejected by the designated approver. Used for SLA measurement, audit trail, and payroll cutoff alignment.',
    `approved_amount` DECIMAL(18,2) COMMENT 'The dollar amount approved by the designated approver after review of the per diem claim. May differ from the claimed amount if the claim exceeds the IRS/GSA rate or client-agreed cap. Feeds payroll non-taxable reimbursement and client billing. Denominated in USD.',
    `billable_to_client` BOOLEAN COMMENT 'Indicates whether the approved per diem amount is billable to the client under the terms of the Master Service Agreement (MSA) or Statement of Work (SOW). When true, the approved amount is included in the client invoice generated in Salesforce Revenue Cloud.',
    `billing_processed` BOOLEAN COMMENT 'Indicates whether the client-billable per diem amount has been included in a client invoice. Prevents duplicate billing and supports reconciliation between per diem claims and accounts receivable records in Oracle NetSuite ERP.',
    `claim_date` DATE COMMENT 'The calendar date on which the per diem expense was incurred by the worker. This is the business event date (not the submission date) and is used for IRS per diem rate lookup, payroll period alignment, and client invoice period matching.',
    `claim_number` STRING COMMENT 'Externally-visible, human-readable business identifier for the per diem claim, used in worker communications, approval workflows, payroll references, and client billing. Format: PDC-{YYYY}-{NNNNNN}.. Valid values are `^PDC-[0-9]{4}-[0-9]{6}$`',
    `claim_status` STRING COMMENT 'Current lifecycle state of the per diem claim within the approval workflow. Drives payroll processing eligibility and client billing inclusion. Valid values: draft, submitted, under_review, approved, rejected, cancelled.. Valid values are `draft|submitted|under_review|approved|rejected|cancelled`',
    `claimed_amount` DECIMAL(18,2) COMMENT 'The gross dollar amount claimed by the worker for the per diem expense. This is the worker-submitted amount before approval review or adjustment. Denominated in USD.',
    `client_bill_amount` DECIMAL(18,2) COMMENT 'The dollar amount to be billed to the client for this per diem claim. May differ from the approved_amount if the client agreement specifies a different reimbursement cap or markup. Denominated in USD. Feeds Salesforce Revenue Cloud invoicing.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this per diem claim record was first created in the system. Serves as the audit trail creation marker for data governance, SOC 2 compliance, and record lineage tracking.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for all monetary amounts on this claim record. Defaults to USD for domestic assignments. Required for international assignments to support multi-currency payroll and billing.. Valid values are `^[A-Z]{3}$`',
    `gsa_locality_code` STRING COMMENT 'The General Services Administration (GSA) locality code corresponding to the expense location. Used to precisely identify the applicable per diem rate tier for the city/county, especially for high-cost localities that exceed the standard continental US (CONUS) rate.',
    `irs_per_diem_rate` DECIMAL(18,2) COMMENT 'The applicable IRS/GSA standard per diem rate for the expense location and claim date at the time of submission. Used as the reference ceiling for non-taxable reimbursement treatment. Amounts at or below this rate are non-taxable; amounts above are treated as taxable wages. Denominated in USD.',
    `irs_rate_year` STRING COMMENT 'The fiscal year of the IRS/GSA per diem rate table used to determine the applicable rate for this claim. IRS per diem rates are updated annually; this field ensures the correct rate schedule is referenced for audit and compliance purposes.',
    `notes` STRING COMMENT 'Free-text field for additional context, worker-provided justification, or operational notes related to the per diem claim. May include travel purpose, special circumstances, or client-specific instructions. Not used for approval decisions.',
    `partial_day_flag` BOOLEAN COMMENT 'Indicates whether the per diem claim is for a partial day (e.g., first or last day of travel). IRS rules require a 75% rate reduction for the first and last day of travel. When true, the claimed amount should reflect the reduced partial-day rate.',
    `payroll_processed` BOOLEAN COMMENT 'Indicates whether the approved per diem reimbursement has been included in a payroll run and disbursed to the worker. Prevents duplicate payroll processing and supports reconciliation between per diem claims and payroll records.',
    `per_diem_type` STRING COMMENT 'Classification of the per diem allowance category being claimed. Determines applicable IRS GSA rate, taxability treatment, and whether the expense is billable to the client. Valid values: travel, lodging, meals, incidentals, meals_and_incidentals (M&IE combined rate).. Valid values are `travel|lodging|meals|incidentals|meals_and_incidentals`',
    `receipt_required` BOOLEAN COMMENT 'Indicates whether a receipt or supporting documentation is required for this per diem claim based on the per diem type, claimed amount, or client policy. Lodging per diem typically requires receipts; meals and incidentals under the GSA rate generally do not.',
    `receipt_submitted` BOOLEAN COMMENT 'Indicates whether the worker has submitted a receipt or supporting documentation for this per diem claim. Used in the approval workflow to enforce receipt requirements and for IRS substantiation compliance.',
    `rejection_reason` STRING COMMENT 'Free-text explanation provided by the approver when a per diem claim is rejected. Required when claim_status is rejected. Supports worker communication, dispute resolution, and process improvement analytics.',
    `source_system` STRING COMMENT 'The operational system of record from which this per diem claim originated. Supports data lineage, reconciliation, and audit traceability across integrated platforms. Valid values: Kronos (Kronos Workforce Ready), TempWorks (TempWorks Payroll), Bullhorn (Bullhorn ATS/CRM), Beeline (Beeline VMS), Manual (direct entry).. Valid values are `Kronos|TempWorks|Bullhorn|Beeline|Manual`',
    `source_system_claim_ref` STRING COMMENT 'The native identifier or reference number assigned to this per diem claim in the originating source system (e.g., Kronos expense record ID, TempWorks reimbursement reference). Supports cross-system reconciliation and data lineage tracing.',
    `submission_timestamp` TIMESTAMP COMMENT 'The date and time when the worker formally submitted the per diem claim for approval. Used for SLA tracking, audit trails, and late-submission compliance monitoring.',
    `taxable_amount` DECIMAL(18,2) COMMENT 'The portion of the approved per diem amount that exceeds the IRS/GSA standard rate and must be treated as taxable wages subject to FICA, FUTA, SUTA, and income tax withholding. Calculated as max(0, approved_amount - irs_per_diem_rate). Feeds TempWorks Payroll tax processing.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this per diem claim record was last modified. Tracks the most recent change for audit trail, data freshness monitoring, and incremental ETL processing in the Databricks Silver Layer.',
    `work_week_ending_date` DATE COMMENT 'The last day of the payroll work week to which this per diem claim belongs. Used to align per diem reimbursements with the correct payroll processing cycle in TempWorks Payroll and to match the corresponding timesheet period.',
    CONSTRAINT pk_per_diem_claim PRIMARY KEY(`per_diem_claim_id`)
) COMMENT 'Records per diem allowance claims submitted by contingent workers for travel, lodging, and meal reimbursements associated with a specific assignment. Captures claim date, per diem type (travel, lodging, meals, incidentals), claimed amount, approved amount, expense location, receipt indicator, approval status, and IRS per diem rate reference. Feeds both payroll (non-taxable reimbursements) and billing (client-billable per diem charges).';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`adjustment` (
    `adjustment_id` BIGINT COMMENT 'Unique system-generated identifier for each timesheet adjustment record. Serves as the primary key for the timesheet_adjustment entity. TRANSACTION_HEADER role — canonical minimum categories enforced.',
    `pay_stub_id` BIGINT COMMENT 'Foreign key linking to payroll.pay_stub. Business justification: Timesheet adjustments often trigger pay stub corrections or reissues. Tracking which specific pay stub was affected (vs. just the pay_run) is essential for audit trails, worker communication about cor',
    `staff_profile_id` BIGINT COMMENT 'Identifier of the user who approved the timesheet adjustment. Required for segregation-of-duties compliance and audit trail. Null if adjustment is pending or rejected.',
    `adjustment_staff_profile_id` BIGINT COMMENT 'Identifier of the user (worker, staffing coordinator, or manager) who initiated the timesheet adjustment request. Required for accountability, audit trail, and workflow routing.',
    `assignment_id` BIGINT COMMENT 'Reference to the active placement or assignment under which the original timesheet was submitted. Links the adjustment to the specific client engagement, job order, and pay/bill rate agreement.',
    `client_account_id` BIGINT COMMENT 'Identifier of the client organization associated with the placement. Required for client billing reconciliation and invoice adjustment when billable hours are corrected.',
    `contract_rate_schedule_id` BIGINT COMMENT 'Foreign key linking to contract.contract_rate_schedule. Business justification: Rate adjustments reference the applicable rate schedule; retroactive rate changes must cite the amended rate schedule for audit trail and billing correction. Real business process: rate correction and',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Adjustments reallocate costs between cost centers when workers are reassigned or time is reclassified. Common in staffing when correcting cost center misallocations; required for accurate client billi',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Adjustments create correcting journal entries that must reference specific GL accounts for audit trail and SOX compliance. Staffing firms require GL-level tracking of all payroll/billing adjustments f',
    `invoice_id` BIGINT COMMENT 'Reference to the client invoice or credit memo generated as a result of this billing adjustment. Links the timesheet correction to the corresponding accounts receivable transaction in Salesforce Revenue Cloud.',
    `pay_run_id` BIGINT COMMENT 'Reference to the payroll run in which this adjustment was processed. Enables reconciliation between timesheet adjustments and payroll output records. Null until the adjustment is applied to payroll.',
    `profile_id` BIGINT COMMENT 'Identifier of the contingent worker whose timesheet is being adjusted. Enables worker-level payroll reconciliation, compliance reporting, and dispute resolution. Supports PARTY_REFERENCE canonical category.',
    `regulatory_violation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_violation. Business justification: Timesheet adjustments may be triggered by wage-hour violations discovered in DOL/state audits (unpaid OT, misclassified hours). Real business process: remediation tracking linking adjustments to viola',
    `timesheet_id` BIGINT COMMENT 'Reference to the original approved timesheet record that this adjustment corrects or amends. Core linkage enabling full audit trail from original submission to corrected values. Maps to the PARTY_REFERENCE canonical category for TRANSACTION_HEADER role.',
    `adjustment_number` STRING COMMENT 'Externally-visible, human-readable business identifier for the adjustment (e.g., ADJ-2024-000123). Used in dispute resolution, payroll reconciliation, and client billing communications. Maps to the BUSINESS_IDENTIFIER canonical category for TRANSACTION_HEADER role.. Valid values are `^ADJ-[0-9]{4}-[0-9]{6}$`',
    `adjustment_status` STRING COMMENT 'Current workflow lifecycle state of the adjustment record. Tracks progression from initial draft through approval and application to payroll and billing. Maps to the LIFECYCLE_STATUS canonical category for TRANSACTION_HEADER role.. Valid values are `draft|submitted|approved|rejected|voided|applied`',
    `adjustment_type` STRING COMMENT 'Categorical classification of the nature of the adjustment. Drives downstream payroll and billing processing logic. [ENUM-REF-CANDIDATE: hours_correction|rate_correction|pay_type_reclassification|retroactive_change|break_correction|absence_correction — promote to reference product if additional types are needed]. Valid values are `hours_correction|rate_correction|pay_type_reclassification|retroactive_change|break_correction|absence_correction`',
    `affects_billing` BOOLEAN COMMENT 'Indicates whether this timesheet adjustment impacts client billable hours or bill rates, triggering a credit memo or supplemental invoice. False for adjustments that only affect worker pay (e.g., internal pay type reclassifications with no billing impact).',
    `affects_payroll` BOOLEAN COMMENT 'Indicates whether this timesheet adjustment impacts worker payable hours or pay rates, requiring a payroll correction or supplemental pay run. False for adjustments that only affect billing (e.g., bill rate corrections with no pay rate change).',
    `applied_to_billing_timestamp` TIMESTAMP COMMENT 'The date and time when the approved adjustment was applied to client billing in Salesforce Revenue Cloud. Null until billing is updated. Confirms the client invoice or credit memo has been generated for the adjustment.',
    `applied_to_payroll_timestamp` TIMESTAMP COMMENT 'The date and time when the approved adjustment was applied to the payroll run in TempWorks Payroll. Null until the adjustment is processed. Confirms the adjustment has been actioned in the payroll system of record.',
    `approval_level` STRING COMMENT 'Indicates the approval tier required for this adjustment based on the adjustment type, dollar impact, or client contract requirements. Single-level approvals are handled internally; dual or client-required approvals involve additional stakeholders.. Valid values are `single|dual|client_required`',
    `approved_timestamp` TIMESTAMP COMMENT 'The date and time when the timesheet adjustment was approved by the designated approver. Null if not yet approved. Used for approval cycle time analytics and SLA compliance reporting.',
    `bill_amount_adjusted` DECIMAL(18,2) COMMENT 'The corrected gross client billing amount (in USD) after the adjustment. Drives credit memo issuance or supplemental invoice generation in Salesforce Revenue Cloud. Part of MONETARY_TRIPLET canonical category.',
    `bill_amount_original` DECIMAL(18,2) COMMENT 'The gross client billing amount (in USD) calculated from the original timesheet hours and bill rate before adjustment. Baseline for client invoice reconciliation and credit memo calculation.',
    `bill_rate_adjusted` DECIMAL(18,2) COMMENT 'The corrected client bill rate (per hour) in USD after the adjustment. Used when a rate correction changes the amount invoiced to the client. Drives credit memo or supplemental invoice generation.',
    `bill_rate_original` DECIMAL(18,2) COMMENT 'The client bill rate (per hour) recorded on the original timesheet, in USD. Preserved for billing reconciliation when rate corrections affect client invoices. Represents the rate charged to the client before adjustment.',
    `client_approved` BOOLEAN COMMENT 'Indicates whether the client has formally approved the timesheet adjustment, required when the adjustment affects billable hours or bill rates under the clients Master Service Agreement (MSA). True when client sign-off is obtained.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this timesheet adjustment record was first created in the system. Maps to the RECORD_AUDIT_CREATED canonical category for TRANSACTION_HEADER role. Used for data lineage and audit trail.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this adjustment record (e.g., USD). Supports multi-currency operations for international staffing engagements. Part of MONETARY_TRIPLET canonical category.. Valid values are `^[A-Z]{3}$`',
    `hours_adjusted` DECIMAL(18,2) COMMENT 'The corrected number of hours after the adjustment is applied. Replaces the original hours value for payroll processing and client billing. The difference between hours_adjusted and hours_original represents the net hours change.',
    `hours_original` DECIMAL(18,2) COMMENT 'The number of hours recorded on the original approved timesheet for the work date and pay type being corrected. Preserved as the pre-adjustment baseline for audit, dispute resolution, and reconciliation.',
    `is_retroactive` BOOLEAN COMMENT 'Indicates whether this adjustment applies to a prior pay period that has already been processed in payroll and/or billing. Retroactive adjustments require special handling in payroll tax recalculation (FICA, FUTA, SUTA) and may trigger amended invoices.',
    `pay_amount_adjusted` DECIMAL(18,2) COMMENT 'The corrected gross worker pay amount (in USD) after the adjustment is applied. Represents the authoritative payable amount for the adjusted period. The difference from pay_amount_original drives payroll debit or credit entries. Maps to MONETARY_TRIPLET canonical category.',
    `pay_amount_original` DECIMAL(18,2) COMMENT 'The gross worker pay amount (in USD) calculated from the original timesheet hours and pay rate before adjustment. Serves as the financial baseline for payroll reconciliation and adjustment impact analysis.',
    `pay_period_end_date` DATE COMMENT 'The last calendar date of the pay period to which this adjustment applies. Together with pay_period_start_date, defines the exact payroll cycle impacted by the correction.',
    `pay_period_start_date` DATE COMMENT 'The first calendar date of the pay period to which this adjustment applies. Determines which payroll run and billing cycle are affected by the correction.',
    `pay_rate_adjusted` DECIMAL(18,2) COMMENT 'The corrected worker pay rate (per hour) in USD after the adjustment. Used for rate correction and retroactive change adjustment types. Drives recalculation of worker gross pay for the affected period.',
    `pay_rate_original` DECIMAL(18,2) COMMENT 'The worker pay rate (per hour) recorded on the original timesheet, in USD. Preserved for rate correction adjustments and retroactive pay rate changes. Sensitive compensation data.',
    `pay_type_adjusted` STRING COMMENT 'The corrected pay type code after adjustment. Used when a pay type reclassification adjustment is applied (e.g., regular hours reclassified as overtime (OT) or double-time (DT)). Drives recalculation of worker pay and client bill amounts. [ENUM-REF-CANDIDATE: regular|overtime|double_time|per_diem|pto|holiday|on_call — 7 candidates stripped; promote to reference product]',
    `pay_type_original` STRING COMMENT 'The pay type code recorded on the original timesheet before adjustment (e.g., regular, overtime (OT), double-time (DT), per diem, paid time off (PTO), holiday, on-call). Preserved for full audit trail and reclassification tracking. [ENUM-REF-CANDIDATE: regular|overtime|double_time|per_diem|pto|holiday|on_call — 7 candidates stripped; promote to reference product]',
    `reason_code` STRING COMMENT 'Standardized reason code categorizing why the timesheet adjustment was initiated. Supports root-cause analysis, compliance reporting, and process improvement. [ENUM-REF-CANDIDATE: data_entry_error|system_error|missed_punch|rate_change|ot_reclassification|client_dispute|worker_dispute|manager_correction — promote to reference product]',
    `reason_notes` STRING COMMENT 'Free-text narrative explanation provided by the requestor describing the specific circumstances requiring the timesheet adjustment. Supplements the reason code with contextual detail for audit and dispute resolution.',
    `requestor_role` STRING COMMENT 'The business role of the individual who submitted the adjustment request. Provides context for approval routing and compliance audit without requiring a join to the user table.. Valid values are `worker|staffing_coordinator|account_manager|client_manager|payroll_admin|system`',
    `source_system` STRING COMMENT 'Identifies the operational system of record that originated or triggered the timesheet adjustment (e.g., Kronos Workforce Ready, Bullhorn, Beeline VMS, TempWorks, or manual entry). Supports data lineage and reconciliation across integrated systems.. Valid values are `kronos|bullhorn|beeline|tempworks|manual`',
    `submitted_timestamp` TIMESTAMP COMMENT 'The date and time when the timesheet adjustment request was formally submitted into the workflow system. Maps to the BUSINESS_EVENT_TIMESTAMP canonical category for TRANSACTION_HEADER role. Used for SLA tracking and audit trail.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this timesheet adjustment record was last modified. Maps to the RECORD_AUDIT_UPDATED canonical category for TRANSACTION_HEADER role. Tracks all changes for compliance and audit purposes.',
    `work_date` DATE COMMENT 'The specific calendar date on which the hours being adjusted were originally worked. Enables day-level audit trail and supports overtime calculation corrections at the daily level.',
    CONSTRAINT pk_adjustment PRIMARY KEY(`adjustment_id`)
) COMMENT 'Records post-submission corrections and amendments to approved timesheets, capturing the original timesheet reference, adjustment type (hours correction, rate correction, pay type reclassification, retroactive change), original values, adjusted values, adjustment reason, requestor, approver, and effective pay period. Maintains a complete audit trail of all timesheet modifications for compliance, dispute resolution, and payroll/billing reconciliation.';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`punch_event` (
    `punch_event_id` BIGINT COMMENT 'Unique surrogate identifier for each individual punch event record in the Kronos Workforce Ready system. Serves as the immutable primary key for this append-only audit-grade event log. Role: EVENT_LOG.',
    `amended_from_punch_punch_event_id` BIGINT COMMENT 'Self-referencing identifier pointing to the original punch event record that this amended record corrects. Null for original (non-amended) punch events. Enables full amendment chain traceability for DOL audit defense and FLSA wage-and-hour dispute resolution. Supports the immutable append-only audit log pattern.',
    `assignment_id` BIGINT COMMENT 'Reference to the active placement or assignment under which the worker is clocking time. Associates the punch event to a specific client engagement, job order, and pay/bill rate context for downstream payroll and billing processing.',
    `cost_center_id` BIGINT COMMENT 'Reference to the client cost center or department to which the workers labor hours are allocated for this punch event. Supports labor cost distribution, client billing by department, and workforce analytics. Particularly relevant for transfer punch types where the worker moves between cost centers mid-shift.',
    `pay_period_id` BIGINT COMMENT 'Reference to the payroll pay period within which this punch event falls. Links the raw punch event to the TempWorks Payroll processing cycle for wage calculation, tax withholding, and W-2 reporting.',
    `staff_profile_id` BIGINT COMMENT 'Reference to the Kronos system user (supervisor, payroll admin, or system process) who created the amendment to this punch event. Null for original punch events. Supports accountability tracking and SOC 2 access control audit requirements.',
    `profile_id` BIGINT COMMENT 'Reference to the contingent worker who performed the punch action. Links to the worker master record for identity resolution, payroll processing, and FLSA compliance reporting.',
    `schedule_id` BIGINT COMMENT 'Reference to the Kronos scheduled shift that this punch event is associated with. Used to calculate schedule adherence, early/late arrival deviations, and unscheduled overtime. Null if the punch was not associated with a pre-defined schedule.',
    `time_entry_id` BIGINT COMMENT 'Foreign key linking to timesheet.time_entry. Business justification: punch_event captures raw clock-in/clock-out events from Kronos, while time_entry is the processed daily time record. Multiple punch events (clock in, clock out, break punches) contribute to a single t',
    `timesheet_id` BIGINT COMMENT 'Reference to the parent timesheet record that aggregates this punch event into a daily or weekly time entry. Multiple punch events roll up into a single timesheet for approval and payroll processing.',
    `work_location_id` BIGINT COMMENT 'Reference to the physical client worksite or facility where the worker is assigned and where the punch event occurred. Used for geofence configuration lookup, workers compensation jurisdiction determination, and site-level labor analytics.',
    `amendment_reason` STRING COMMENT 'Categorized reason code explaining why this punch event record was created as an amendment to a prior punch. Null for original punch events. Required for DOL audit defense and internal compliance review. [ENUM-REF-CANDIDATE: missed_punch|device_failure|system_error|supervisor_correction|worker_request|schedule_adjustment|other — promote to reference product]',
    `amendment_timestamp` TIMESTAMP COMMENT 'The UTC timestamp when the amendment to this punch event was recorded in Kronos. Null for original punch events. Provides the audit trail timestamp for change management and DOL recordkeeping compliance.',
    `approval_timestamp` TIMESTAMP COMMENT 'The UTC timestamp when the punch event was approved by a supervisor or auto-approved by the system. Null if not yet approved. Marks the point at which the punch event becomes eligible for inclusion in payroll processing and client billing.',
    `billable_flag` BOOLEAN COMMENT 'Indicates whether the hours associated with this punch event are billable to the client. True: hours are billable and will feed Salesforce Revenue Cloud invoicing; False: non-billable (e.g., orientation, training, administrative time). Drives client billing eligibility in the downstream billing pipeline.',
    `biometric_verified` BOOLEAN COMMENT 'Indicates whether the punch event was authenticated via biometric verification (fingerprint scan, facial recognition) on the Kronos time clock. True: biometric match confirmed worker identity; False: biometric check failed or was bypassed. Null if the device does not support biometric authentication. Critical for buddy-punch prevention and FLSA compliance.',
    `device_code` STRING COMMENT 'Unique identifier of the Kronos time clock hardware, mobile application instance, or web portal session that captured the punch event. Used for device-level audit trails, buddy-punch fraud detection, and equipment management. Sourced directly from the Kronos Workforce Ready device registry.',
    `exception_flag` BOOLEAN COMMENT 'Indicates whether this punch event triggered one or more Kronos exception conditions (e.g., missed punch, early in, late out, geofence violation, unscheduled punch). True: one or more exceptions exist; False: no exceptions. Drives exception queue routing for supervisor review and payroll hold workflows.',
    `exception_type` STRING COMMENT 'The specific type of exception condition triggered by this punch event in Kronos. Examples include: missed_punch, early_in, late_in, early_out, late_out, long_break, short_break, geofence_violation, unscheduled_punch. Null if exception_flag is False. [ENUM-REF-CANDIDATE: missed_punch|early_in|late_in|early_out|late_out|long_break|short_break|geofence_violation|unscheduled_punch — promote to reference product]',
    `flsa_workweek_start_date` DATE COMMENT 'The start date of the FLSA-defined 7-consecutive-day workweek period within which this punch event falls. The FLSA workweek is fixed and recurring, defined per employer or client site. Critical for accurate overtime calculation — OT is calculated per workweek, not per pay period.',
    `geofence_validated` BOOLEAN COMMENT 'Indicates whether the punch event location coordinates fell within the approved geofence boundary for the assigned worksite at the time of the punch. True: worker was within the geofenced zone; False: worker was outside the boundary, triggering an exception alert. Null if geofence validation was not applicable (e.g., physical time clock punch).',
    `grace_period_applied` BOOLEAN COMMENT 'Indicates whether a Kronos grace period rule was applied to this punch event, allowing a small window (e.g., 5 minutes) before or after the scheduled time without triggering an exception or early/late flag. Supports schedule adherence reporting accuracy.',
    `ingestion_timestamp` TIMESTAMP COMMENT 'The UTC timestamp when this punch event record was first ingested into the Databricks Silver layer from the Kronos source system. Serves as the RECORD_AUDIT_CREATED marker for data lineage, SLA monitoring of data pipeline latency, and audit trail completeness.',
    `ip_address` STRING COMMENT 'The IP address of the device or network from which the punch event was submitted (applicable for web portal and mobile app punches). Used for fraud detection, buddy-punch investigation, and network-level audit trails. May be considered PII under GDPR and CCPA in some jurisdictions.',
    `job_code` STRING COMMENT 'The Kronos job code or labor category code associated with the work being performed at the time of the punch. Drives pay rate selection, bill rate application, and FLSA overtime classification. May change on a transfer punch when the worker switches tasks or roles mid-shift.',
    `kronos_punch_ref` STRING COMMENT 'The native punch event identifier assigned by the Kronos Workforce Ready source system. Preserved for cross-system reconciliation, data lineage tracing, and support ticket resolution. Enables exact record matching between the Databricks Silver layer and the Kronos operational system.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The UTC timestamp when this punch event record was last modified in the Databricks Silver layer (e.g., status update from raw to validated, amendment applied). Supports incremental data pipeline processing and audit trail completeness.',
    `latitude` DECIMAL(18,2) COMMENT 'GPS latitude coordinate (WGS-84 decimal degrees) captured at the moment of the punch event from a mobile device or GPS-enabled time clock. Used for geofence validation to confirm the worker was physically present at the designated worksite. Null if the device does not support GPS.',
    `location_accuracy_meters` DECIMAL(18,2) COMMENT 'The GPS accuracy radius in meters reported by the mobile device at the time of the punch event. Lower values indicate higher precision. Used to qualify geofence validation results — punches with accuracy radius exceeding the geofence boundary tolerance may be flagged for manual review.',
    `longitude` DECIMAL(18,2) COMMENT 'GPS longitude coordinate (WGS-84 decimal degrees) captured at the moment of the punch event from a mobile device or GPS-enabled time clock. Paired with latitude for geofence boundary validation and worksite presence verification.',
    `pay_type` STRING COMMENT 'Classification of the pay category applicable to the hours captured by this punch event. regular: standard straight-time hours; overtime (OT): hours exceeding FLSA or state OT thresholds; double_time (DT): hours qualifying for double-time premium; per_diem: expense reimbursement-based pay; holiday: holiday premium pay; pto: Paid Time Off. Drives pay rate multiplier selection in TempWorks Payroll.. Valid values are `regular|overtime|double_time|per_diem|holiday|pto`',
    `punch_source` STRING COMMENT 'The channel or interface through which the punch event was submitted. time_clock: physical Kronos hardware terminal; mobile_app: Kronos mobile application; web_portal: browser-based Kronos portal; supervisor_entry: manually entered by a supervisor on behalf of the worker; api: submitted via system integration. Supports fraud detection and channel-level analytics.. Valid values are `time_clock|mobile_app|web_portal|supervisor_entry|api`',
    `punch_status` STRING COMMENT 'Current processing state of the punch event record. raw: received from source device, not yet validated; validated: passed geofence, biometric, and schedule checks; amended: manually corrected by supervisor or payroll admin; rejected: failed validation rules; voided: nullified for audit purposes. Drives downstream time_entry aggregation eligibility.. Valid values are `raw|validated|amended|rejected|voided`',
    `punch_timestamp` TIMESTAMP COMMENT 'The exact UTC timestamp when the worker performed the clock action (punch-in, punch-out, break start, break end, or transfer). This is the authoritative real-world event time used for FLSA wage-and-hour calculations, DOL audit defense, and overtime determination. Stored in UTC per ISO 8601.',
    `punch_type` STRING COMMENT 'Discriminator indicating the nature of the clock action recorded. clock_in: worker begins a work period; clock_out: worker ends a work period; break_start: worker begins an unpaid or paid break; break_end: worker resumes work after a break; transfer: worker moves between cost centers, departments, or job codes mid-shift. Drives FLSA break compliance and hours calculation logic.. Valid values are `clock_in|clock_out|break_start|break_end|transfer`',
    `raw_payload` STRING COMMENT 'The complete raw JSON or XML payload received from the Kronos Workforce Ready source system for this punch event. Stored as an immutable string to support full audit reconstruction, dispute resolution, and re-processing in the event of transformation errors. Retention: minimum 3 years per FLSA recordkeeping requirements.',
    `rounded_punch_timestamp` TIMESTAMP COMMENT 'The effective punch timestamp after application of the configured Kronos rounding rule. Used as the basis for hours calculation in time_entry aggregation. Null if rounding_rule_applied is False. Stored separately from the raw punch_timestamp to preserve the original immutable record for FLSA audit defense.',
    `rounding_rule_applied` BOOLEAN COMMENT 'Indicates whether a Kronos time rounding rule was applied to the raw punch timestamp to produce the effective time used in hours calculations. True: rounding was applied (e.g., nearest 15-minute increment); False: raw timestamp used as-is. FLSA permits rounding only when it averages out over time and does not systematically undercount hours.',
    `scheduled_end_time` TIMESTAMP COMMENT 'The UTC timestamp of the workers scheduled shift end time as defined in Kronos. Compared against the actual clock-out punch_timestamp to calculate early departure or overtime variance for schedule adherence and FLSA overtime analysis.',
    `scheduled_start_time` TIMESTAMP COMMENT 'The UTC timestamp of the workers scheduled shift start time as defined in Kronos. Compared against the actual punch_timestamp to calculate early/late arrival variance for schedule adherence reporting and SLA compliance tracking.',
    `time_zone` STRING COMMENT 'The IANA time zone identifier (e.g., America/Chicago, America/New_York) of the worksite where the punch event occurred. Required to correctly convert UTC punch_timestamp to local work date for FLSA workweek boundary calculations and state wage-and-hour law compliance.',
    `work_date` DATE COMMENT 'The calendar date (in the workers local time zone) on which the punch event occurred. Used for daily timesheet aggregation, FLSA workweek calculations, overtime determination, and client billing period alignment. Derived from punch_timestamp adjusted to the sites configured time zone.',
    CONSTRAINT pk_punch_event PRIMARY KEY(`punch_event_id`)
) COMMENT 'Raw, immutable clock event record capturing individual worker punch-in and punch-out events from Kronos Workforce Ready time clocks, mobile apps, or web portals. Stores the exact UTC timestamp, punch type (in/out/break-start/break-end/transfer), device ID, location coordinates, geofence validation result, biometric verification flag, IP address, and raw source payload. Multiple punch events are processed into a single time_entry record. Serves as the tamper-proof audit-grade source record for FLSA compliance, wage-and-hour dispute resolution, and DOL audit defense. Retention policy: minimum 3 years per FLSA recordkeeping requirements.';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`labor_category` (
    `labor_category_id` BIGINT COMMENT 'Unique surrogate identifier for the labor category record. Primary key for the labor_category reference entity. [_canonical_skip_reason: Entity role is REFERENCE_LOOKUP — a reference/code table defining labor classifications; per-role minimums are exempt, but MASTER_RESOURCE categories are applied given the entity carries substantive business attributes beyond a simple enumeration.]',
    `contract_rate_schedule_id` BIGINT COMMENT 'Foreign key linking to contract.contract_rate_schedule. Business justification: Labor categories map to rate schedule job categories; rate schedules define bill/pay rates per labor category for contract compliance. Real business process: rate card mapping and labor category prici',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Labor categories may have default cost center mappings for specific service lines or client types. Enables automated cost center allocation rules in staffing operations; common for standardized client',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Labor categories map to GL accounts for standardized expense classification across engagements. Staffing firms use labor category-to-GL mappings for consistent financial reporting and automated timesh',
    `ot_rule_id` BIGINT COMMENT 'Reference to the overtime rule set applicable to this labor category. Determines how overtime hours are calculated (e.g., daily OT after 8 hours, weekly OT after 40 hours, California daily/weekly OT rules). Links to the ot_rule reference entity as specified in the product description.',
    `vendor_rate_card_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor_rate_card. Business justification: Labor categories must map to vendor-specific rate cards for rate validation, margin analysis, and vendor bill rate verification. When evaluating vendor submissions or processing timesheets, staffing f',
    `wage_hour_determination_id` BIGINT COMMENT 'Foreign key linking to compliance.wage_hour_determination. Business justification: Labor categories must have validated wage-hour determinations (FLSA classification, prevailing wage, exempt status). Rate cards cannot be published without determination. Real business process: compli',
    `approved_by` STRING COMMENT 'Name or identifier of the business user or manager who approved this labor category definition and its associated rates. Required for governance and audit compliance in rate card management.',
    `approved_date` DATE COMMENT 'Date on which this labor category record was formally approved by the designated approver. Used for governance, audit trail, and effective dating validation.',
    `billable_indicator` BOOLEAN COMMENT 'Flag indicating whether time entries coded to this labor category are billable to the client. When true, hours are included in client invoicing. When false, hours are internal or non-billable (e.g., orientation, training, bench time).',
    `burden_rate_pct` DECIMAL(18,2) COMMENT 'The total employer burden rate percentage applied to the base pay rate for workers in this labor category. Includes employer-side FICA, FUTA, SUTA, workers comp, and benefits costs expressed as a percentage of base pay. Used for gross margin and spread analysis.',
    `category_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the labor category. Used in timesheets, billing systems, and VMS integrations to reference the category. Sourced from Kronos Workforce Ready and synchronized to Beeline VMS and Salesforce Revenue Cloud.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `category_description` STRING COMMENT 'Detailed narrative description of the labor category, including scope of work, typical duties, and applicable skill requirements. Used for client-facing documentation, MSA exhibits, and SOW labor category definitions.',
    `category_name` STRING COMMENT 'Human-readable name of the labor category (e.g., Software Engineer – Senior, Light Industrial – Forklift Operator, Administrative – Data Entry). Displayed in timesheets, client invoices, and workforce analytics dashboards.',
    `category_type` STRING COMMENT 'Broad classification grouping the labor category into a workforce segment (e.g., professional, light industrial, clerical, technical, healthcare, executive, skilled trades). Drives workforce analytics segmentation and client billing tier assignment. [ENUM-REF-CANDIDATE: professional|light_industrial|clerical|technical|healthcare|executive|skilled_trades — promote to reference product if additional values are needed]',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this labor category record was first created in the system. Used for audit trail, data lineage, and record lifecycle management in the Databricks Lakehouse silver layer.',
    `default_bill_rate` DECIMAL(18,2) COMMENT 'Default hourly bill rate (in USD) charged to the client for workers assigned to this labor category. Serves as the baseline rate before client-specific or contract-specific overrides are applied. Used by Salesforce Revenue Cloud for invoice generation.',
    `default_dt_bill_rate` DECIMAL(18,2) COMMENT 'Default hourly double-time (DT) bill rate charged to the client for double-time hours worked by workers in this labor category. Applicable in states or contracts requiring double-time pay (e.g., California labor law).',
    `default_dt_pay_rate` DECIMAL(18,2) COMMENT 'Default hourly double-time (DT) pay rate paid to workers in this labor category for double-time hours. Applicable under state-specific labor laws or union agreements requiring double-time compensation.',
    `default_ot_bill_rate` DECIMAL(18,2) COMMENT 'Default hourly overtime (OT) bill rate charged to the client for overtime hours worked by workers in this labor category. Typically 1.5x the standard bill rate unless a client-specific rate card overrides it.',
    `default_ot_pay_rate` DECIMAL(18,2) COMMENT 'Default hourly overtime (OT) pay rate paid to workers in this labor category for overtime hours. Must comply with FLSA overtime requirements (minimum 1.5x regular rate for non-exempt workers).',
    `default_pay_rate` DECIMAL(18,2) COMMENT 'Default hourly pay rate (in USD) paid to workers assigned to this labor category. Serves as the baseline rate before worker-specific or assignment-specific overrides are applied. Used by TempWorks Payroll for compensation calculation.',
    `eeo_job_category` STRING COMMENT 'EEOC EEO-1 job category assigned to this labor category for equal employment opportunity reporting. Required for federal contractors and employers with 100+ employees. [ENUM-REF-CANDIDATE: executives_senior_officials|first_mid_officials|professionals|technicians|sales_workers|administrative_support|craft_workers|operatives|laborers_helpers|service_workers — promote to reference product]',
    `effective_date` DATE COMMENT 'The date from which this labor category definition and its associated rates become effective. Supports rate versioning and historical rate lookups for timesheet processing and billing reconciliation.',
    `expiration_date` DATE COMMENT 'The date on which this labor category definition and its associated rates expire. Null for open-ended categories. After this date, the category is no longer available for new timesheet entries unless renewed or superseded.',
    `flsa_classification` STRING COMMENT 'Indicates whether workers in this labor category are classified as exempt or non-exempt under the Fair Labor Standards Act (FLSA). Non-exempt workers are entitled to overtime pay; exempt workers are not. Critical for overtime rule application and payroll compliance.. Valid values are `exempt|non_exempt`',
    `ic_eligible` BOOLEAN COMMENT 'Flag indicating whether workers in this labor category may be engaged as independent contractors (1099) rather than W-2 employees. Drives worker classification compliance checks per IRS worker classification rules and DOL economic reality test.',
    `job_function_code` STRING COMMENT 'Standardized job function code classifying the primary work function of this labor category (e.g., IT, Finance, Operations, Engineering, Healthcare). Aligns with O*NET or SOC occupational classification codes for workforce analytics and regulatory reporting.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `kronos_labor_category_ref` STRING COMMENT 'The native labor category identifier in Kronos Workforce Ready, the system of record for time and attendance. Used for system integration and data lineage tracing between the lakehouse silver layer and the Kronos source system.. Valid values are `^[A-Z0-9_-]{1,50}$`',
    `labor_category_status` STRING COMMENT 'Current lifecycle status of the labor category record. active indicates the category is available for use in timesheet entries and billing; inactive indicates it has been retired; pending indicates it is awaiting approval; deprecated indicates it has been superseded by a newer category.. Valid values are `active|inactive|pending|deprecated`',
    `markup_pct` DECIMAL(18,2) COMMENT 'Default markup percentage applied over the pay rate to derive the bill rate for this labor category. Represents the spread as a percentage of pay rate. Used in pricing models and profitability analysis. Markup = (Bill Rate - Pay Rate) / Pay Rate × 100.',
    `max_bill_rate` DECIMAL(18,2) COMMENT 'Maximum allowable hourly bill rate for this labor category. Used as a ceiling in VMS rate card negotiations and client contract management. Bill rates above this ceiling require management approval.',
    `min_pay_rate` DECIMAL(18,2) COMMENT 'Minimum allowable hourly pay rate for workers assigned to this labor category. Enforces compliance with applicable federal, state, or local minimum wage laws and prevailing wage requirements. Pay rates below this floor are rejected during payroll processing.',
    `per_diem_eligible` BOOLEAN COMMENT 'Flag indicating whether workers assigned to this labor category are eligible for per diem allowances (daily expense reimbursements for travel, lodging, or meals). Affects payroll processing and client billing for travel-based assignments.',
    `prevailing_wage_indicator` BOOLEAN COMMENT 'Flag indicating whether this labor category is subject to prevailing wage requirements under the Davis-Bacon Act or Service Contract Act (SCA) for government or federally funded contracts. When true, the prevailing_wage_rate field applies.',
    `prevailing_wage_rate` DECIMAL(18,2) COMMENT 'The federally or state-mandated prevailing wage rate (in USD per hour) applicable to this labor category for government or public works contracts. Determined by DOL wage determinations under the Davis-Bacon Act or SCA. Null when prevailing_wage_indicator is false.',
    `rate_tier_code` STRING COMMENT 'Code identifying the default bill/pay rate tier associated with this labor category. Rate tiers define pricing bands used across client contracts and VMS programs. Links to rate tier configuration in Beeline VMS and Salesforce Revenue Cloud.. Valid values are `^[A-Z0-9_-]{1,10}$`',
    `sca_labor_category_code` STRING COMMENT 'The official Service Contract Act (SCA) labor category code or title as defined in the applicable DOL wage determination. Used to map internal labor categories to SCA-compliant job classifications for federal service contracts. Required for compliance reporting on government staffing contracts.. Valid values are `^[A-Z0-9 /-]{2,50}$`',
    `skill_level` STRING COMMENT 'Proficiency or seniority tier associated with the labor category (e.g., entry, junior, mid, senior, lead, principal, executive). Used to differentiate bill/pay rate tiers and to support workforce planning analytics. [ENUM-REF-CANDIDATE: entry|junior|mid|senior|lead|principal|executive — promote to reference product if additional values are needed]',
    `soc_code` STRING COMMENT 'U.S. Bureau of Labor Statistics Standard Occupational Classification (SOC) code mapped to this labor category. Used for EEOC reporting, DOL compliance, workforce analytics, and labor market benchmarking. Format: XX-XXXX (e.g., 15-1252 for Software Developers).. Valid values are `^[0-9]{2}-[0-9]{4}$`',
    `temp_to_perm_eligible` BOOLEAN COMMENT 'Flag indicating whether placements in this labor category are eligible for temp-to-perm conversion (contract-to-hire). When true, a conversion fee may apply upon permanent placement. Used in Bullhorn ATS/CRM for placement tracking and conversion fee calculation.',
    `union_applicable` BOOLEAN COMMENT 'Flag indicating whether this labor category is subject to a collective bargaining agreement (CBA) or union work rules. When true, the union_code field identifies the applicable union. Affects pay rates, overtime rules, and benefit requirements.',
    `union_code` STRING COMMENT 'Code identifying the labor union or collective bargaining agreement (CBA) applicable to this labor category. Null when union_applicable is false. Used to apply union-specific pay rules, benefit contributions, and work rules in payroll processing.. Valid values are `^[A-Z0-9_-]{1,20}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this labor category record was last modified. Used for change detection, incremental data loading, and audit trail maintenance in the Databricks Lakehouse silver layer.',
    `vms_category_code` STRING COMMENT 'The labor category code as defined in the clients Vendor Management System (VMS), specifically Beeline VMS. Used to map internal labor categories to VMS-defined categories for contingent workforce program management and rate card alignment.. Valid values are `^[A-Z0-9_-]{1,30}$`',
    `workers_comp_code` STRING COMMENT 'NCCI (National Council on Compensation Insurance) workers compensation class code associated with this labor category. Determines the workers comp insurance rate applied to payroll for workers in this category. Used by TempWorks Payroll for burden rate calculation.. Valid values are `^[0-9]{4,6}$`',
    CONSTRAINT pk_labor_category PRIMARY KEY(`labor_category_id`)
) COMMENT 'Reference entity defining labor categories and work classifications used to categorize time entries for cost allocation, billing rate determination, and workforce analytics. Captures category code, category name, skill level, FLSA classification (exempt/non-exempt), prevailing wage indicator, prevailing wage rate (for Davis-Bacon Act compliance on government staffing contracts), union code applicability, SCA (Service Contract Act) labor category mapping, and default bill/pay rate tier. Used by clients and staffing operations to segment labor costs by function, skill, or contract type. Links to ot_rule for determining applicable overtime calculation rules.';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`timesheet_dispute` (
    `timesheet_dispute_id` BIGINT COMMENT 'Unique system-generated identifier for each timesheet dispute record. Primary key for the timesheet_dispute data product. TRANSACTION_HEADER role entity.',
    `adjustment_id` BIGINT COMMENT 'Foreign key linking to timesheet.timesheet_adjustment. Business justification: timesheet_dispute tracks formal disputes raised against timesheets. When a dispute is resolved, it often results in a timesheet_adjustment. This FK links the dispute to the adjustment that resolved it',
    `assignment_id` BIGINT COMMENT 'Reference to the active placement or assignment under which the disputed timesheet was submitted. Ties the dispute to the specific job order and client engagement.',
    `billing_adjustment_id` BIGINT COMMENT 'Reference to the billing adjustment or credit memo created in Salesforce Revenue Cloud as a result of the dispute resolution. Null until the dispute is resolved and a billing correction is issued to the client.',
    `client_account_id` BIGINT COMMENT 'Identifier of the client organization associated with the disputed timesheet. Used for client-facing SLA tracking and billing dispute resolution.',
    `pay_adjustment_id` BIGINT COMMENT 'Reference to the payroll adjustment transaction created in TempWorks Payroll as a result of the dispute resolution. Null until the dispute is resolved and a payroll correction is processed.',
    `profile_id` BIGINT COMMENT 'Identifier of the contingent worker whose timesheet is under dispute. Used to associate the dispute with the workers placement and payroll records.',
    `regulatory_violation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_violation. Business justification: Timesheet disputes may escalate to regulatory violations (unpaid wages, misclassification claims filed with DOL/state agencies). Real business process: dispute escalation tracking linking worker compl',
    `staff_profile_id` BIGINT COMMENT 'Identifier of the specific internal staff member (coordinator, payroll analyst, or client manager) currently assigned to work the dispute. Enables individual-level SLA tracking and workload reporting.',
    `timesheet_id` BIGINT COMMENT 'Reference to the specific timesheet record that is the subject of this dispute. Links the dispute to the authoritative hours record in Kronos Workforce Ready.',
    `bill_rate` DECIMAL(18,2) COMMENT 'The hourly bill rate charged to the client for the disputed timesheet period. Used to calculate the billable adjustment amount for client invoicing. Sourced from Beeline VMS or the client contract.',
    `claimed_hours` DECIMAL(18,2) COMMENT 'The number of hours the dispute initiator asserts should have been recorded. Compared against recorded_hours to determine the hours discrepancy and calculate the disputed pay or bill amount.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the dispute record was first created in the data platform. Used for audit trail and data lineage. May differ from submitted_timestamp if there is a processing lag.',
    `dispute_number` STRING COMMENT 'Externally-visible, human-readable reference number assigned to the dispute at creation. Used in worker and client communications, back-office tracking, and SLA reporting. Format: DISP- followed by 8–12 digits.. Valid values are `^DISP-[0-9]{8,12}$`',
    `dispute_status` STRING COMMENT 'Current lifecycle state of the dispute. Drives SLA tracking and operational dashboards. Values: open (newly raised), under_review (being investigated), resolved (outcome determined), escalated (elevated to senior staff or client), withdrawn (initiator retracted), closed (finalized with no further action).. Valid values are `open|under_review|resolved|escalated|withdrawn|closed`',
    `dispute_type` STRING COMMENT 'Classification of the nature of the dispute. Drives routing, resolution workflow, and compliance reporting. Values: hours_discrepancy (worker claims hours differ from recorded), rate_dispute (bill rate or pay rate is incorrect), missing_time (hours not captured), unauthorized_ot (overtime not pre-approved), per_diem_dispute (per diem amount contested), other.. Valid values are `hours_discrepancy|rate_dispute|missing_time|unauthorized_ot|per_diem_dispute|other`',
    `disputed_amount` DECIMAL(18,2) COMMENT 'The gross monetary value under dispute, expressed in USD. Calculated as the difference between the claimed and recorded hours multiplied by the applicable pay or bill rate. Used for payroll adjustment and client billing reconciliation.',
    `disputed_hours` DECIMAL(18,2) COMMENT 'The number of hours being contested in the dispute. Represents the delta between what the worker claims and what was recorded, or the total hours in question for missing-time disputes. Used for payroll adjustment calculations.',
    `disputed_work_date` DATE COMMENT 'The specific calendar date on the timesheet that is being disputed. For multi-day disputes, this represents the start date of the disputed period.',
    `disputed_work_date_end` DATE COMMENT 'The end date of the disputed work period for multi-day disputes. Null for single-day disputes. Together with disputed_work_date defines the full disputed pay period window.',
    `dt_hours_disputed` DECIMAL(18,2) COMMENT 'The number of double-time hours specifically contested within the dispute. Applicable in states or contracts where double-time rates apply (e.g., California labor law). Null if no double-time hours are in dispute.',
    `escalation_flag` BOOLEAN COMMENT 'Indicates whether the dispute has been escalated beyond the standard resolution workflow (e.g., to senior management, legal, or the clients MSP/VMS program). True when dispute_status is escalated or when SLA breach has occurred.',
    `escalation_reason` STRING COMMENT 'Free-text description of why the dispute was escalated. Captured when escalation_flag is True. Includes reasons such as SLA breach, high monetary value, repeated dispute by same worker, or client-requested escalation.',
    `escalation_timestamp` TIMESTAMP COMMENT 'The date and time when the dispute was escalated. Used to measure escalation response time and track SLA compliance from the point of escalation.',
    `initiated_by` STRING COMMENT 'Party who raised the dispute. Determines the communication and resolution workflow. Values: worker (contingent worker self-reported), client (client contact raised the issue), back_office (internal staffing coordinator identified discrepancy), system (automated detection via Kronos or payroll reconciliation).. Valid values are `worker|client|back_office|system`',
    `initiator_name` STRING COMMENT 'Full name of the individual who raised the dispute (worker name, client contact name, or back-office staff name). Captured at time of submission for audit trail purposes.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the dispute record. Tracks status changes, note additions, and resolution updates for audit and SLA compliance.',
    `ot_hours_disputed` DECIMAL(18,2) COMMENT 'The number of overtime hours specifically contested within the dispute. Relevant for unauthorized_ot dispute types where the client or back-office challenges OT hours that were not pre-approved. Governed by FLSA overtime provisions.',
    `pay_rate` DECIMAL(18,2) COMMENT 'The workers hourly pay rate applicable to the disputed timesheet period. Used to calculate the payable adjustment amount for the worker. Sourced from TempWorks Payroll and the placement record.',
    `per_diem_amount_disputed` DECIMAL(18,2) COMMENT 'The per diem reimbursement amount being contested in the dispute. Applicable when dispute_type is per_diem_dispute. Per diem rates are governed by IRS guidelines and client MSA terms.',
    `prior_dispute_count` STRING COMMENT 'The number of previously submitted disputes associated with the same worker and placement at the time this dispute was raised. Used for risk flagging, pattern detection, and compliance reporting. A high count may indicate a systemic timekeeping issue.',
    `recorded_hours` DECIMAL(18,2) COMMENT 'The number of hours as originally recorded on the timesheet at the time the dispute was raised. Provides the baseline for comparison against the workers or clients claimed hours.',
    `resolution_date` DATE COMMENT 'The calendar date on which the dispute was formally resolved and a resolution_outcome was recorded. Used to calculate actual resolution cycle time against SLA targets.',
    `resolution_notes` STRING COMMENT 'Free-text narrative documenting the findings, evidence reviewed, and rationale for the resolution outcome. Captured by the resolving party and retained for compliance and audit purposes.',
    `resolution_outcome` STRING COMMENT 'The final determination of the dispute. Values: approved_in_full (all disputed hours/amounts accepted), approved_partial (partial adjustment granted), denied (dispute rejected), withdrawn (initiator retracted before resolution), no_action_required (investigation found no discrepancy). Null while dispute is open or under review.. Valid values are `approved_in_full|approved_partial|denied|withdrawn|no_action_required`',
    `resolved_amount` DECIMAL(18,2) COMMENT 'The final monetary adjustment amount approved as a result of the dispute resolution. Drives payroll correction entries in TempWorks and billing adjustments in Salesforce Revenue Cloud. Null until resolution_outcome is set.',
    `resolved_hours` DECIMAL(18,2) COMMENT 'The final agreed-upon number of hours after dispute resolution. May equal claimed_hours (full approval), a value between recorded_hours and claimed_hours (partial), or recorded_hours (denial). Used to drive payroll and billing adjustments.',
    `responsible_party` STRING COMMENT 'The internal role or team currently responsible for investigating and resolving the dispute. Used for workload assignment, SLA accountability, and escalation routing. Values: staffing_coordinator, payroll_team, client_manager, vms_admin, escalation_team.. Valid values are `staffing_coordinator|payroll_team|client_manager|vms_admin|escalation_team`',
    `sla_breach_flag` BOOLEAN COMMENT 'Indicates whether the dispute resolution exceeded the defined SLA target hours. True when the dispute was not resolved within sla_target_hours of submitted_timestamp. Feeds SLA compliance reporting and client KPI dashboards.',
    `sla_target_hours` STRING COMMENT 'The contractually or operationally defined number of business hours within which the dispute must be resolved. Sourced from the client MSA or internal SLA policy. Used to calculate SLA compliance and breach status.',
    `source_channel` STRING COMMENT 'The channel through which the dispute was submitted. Values: portal (worker or client self-service portal), email (submitted via email to back-office), phone (verbal submission logged by coordinator), vms (raised through Beeline VMS), ats (raised through Bullhorn ATS/CRM), manual (back-office data entry). Used for channel analytics and process improvement.. Valid values are `portal|email|phone|vms|ats|manual`',
    `submitted_timestamp` TIMESTAMP COMMENT 'The exact date and time when the dispute was formally submitted into the system. This is the principal business event timestamp used as the SLA clock start for dispute resolution tracking.',
    `supporting_document_flag` BOOLEAN COMMENT 'Indicates whether supporting documentation (e.g., badge swipe records, supervisor sign-off, email correspondence, system logs) has been attached to the dispute record. True when at least one document has been submitted as evidence.',
    `timesheet_week_ending_date` DATE COMMENT 'The week-ending date of the pay period associated with the disputed timesheet. Used to align the dispute with the correct payroll cycle and billing period for adjustment processing.',
    `vms_dispute_reference` STRING COMMENT 'The dispute or ticket reference number assigned by the clients VMS platform (e.g., Beeline) when the dispute was raised through a managed service program. Enables cross-system traceability for MSP/VMS-managed accounts. Null for non-VMS clients.',
    CONSTRAINT pk_timesheet_dispute PRIMARY KEY(`timesheet_dispute_id`)
) COMMENT 'Tracks formal disputes raised by workers or clients against submitted or approved timesheets. Captures dispute type (hours discrepancy, rate dispute, missing time, unauthorized OT), dispute initiator (worker, client, back-office), disputed timesheet reference, disputed amount, dispute status (open, under review, resolved, escalated), resolution outcome, resolution date, and responsible party. Supports SLA tracking for dispute resolution and feeds compliance reporting.';

CREATE OR REPLACE TABLE `staffing_hr_ecm`.`timesheet`.`vms_timesheet_sync` (
    `vms_timesheet_sync_id` BIGINT COMMENT 'Unique surrogate primary key for each VMS timesheet synchronization record in the Staffing Hr lakehouse Silver layer. Entity role: TRANSACTION_HEADER — represents a discrete sync event with its own lifecycle between Kronos Workforce Ready and a client VMS platform.',
    `assignment_id` BIGINT COMMENT 'Reference to the contingent worker placement record associated with this timesheet sync. Identifies the specific assignment under which the worker submitted hours, linking the sync event to the placement lifecycle in Bullhorn ATS/CRM.',
    `client_account_id` BIGINT COMMENT 'Reference to the client organization whose VMS platform is the target or source of this synchronization. Identifies the MSP/VMS-managed program client for billing dispute resolution and program reporting.',
    `managed_program_id` BIGINT COMMENT 'Foreign key linking to client.managed_program. Business justification: VMS sync occurs within managed programs (MSP/RPO); program-specific integration rules and SLA tracking require this link. Essential for managed program performance reporting and program-specific VMS r',
    `profile_id` BIGINT COMMENT 'Reference to the contingent worker whose timesheet hours are being synchronized. Enables worker-level reconciliation reporting and audit trails for payroll and billing accuracy.',
    `timesheet_id` BIGINT COMMENT 'Reference to the internal Kronos Workforce Ready timesheet record being synchronized. Links this sync event to the authoritative timesheet in the internal time-and-attendance system.',
    `vms_enrollment_id` BIGINT COMMENT 'Foreign key linking to vendor.vms_enrollment. Business justification: VMS timesheet synchronization requires vendor enrollment context to route data correctly to VMS platforms (Fieldglass, Beeline). Integration middleware must identify which vendor enrollment applies to',
    `vms_program_id` BIGINT COMMENT 'The identifier of the MSP/VMS-managed contingent workforce program within the VMS platform. Used to segment sync records by client program for program-level reporting, SLA tracking, and billing reconciliation under MSP agreements.',
    `approval_status` STRING COMMENT 'The approval state of the timesheet within the client VMS platform. pending = awaiting client manager approval; approved = client approved in VMS; rejected = client rejected in VMS; disputed = under active dispute; recalled = previously approved but recalled for correction. Drives billing eligibility.. Valid values are `pending|approved|rejected|disputed|recalled`',
    `bill_rate` DECIMAL(18,2) COMMENT 'The hourly bill rate applied to this timesheet for client invoicing purposes, as agreed in the MSA or VMS rate card. Used to validate that the rate applied in the VMS matches the contracted rate in Kronos/Bullhorn. A mismatch triggers a billing dispute.',
    `cost_center_code` STRING COMMENT 'The client cost center code associated with this timesheet as recorded in the VMS platform. Used for client-side labor cost allocation and is a common source of field-level mapping discrepancies between Kronos and VMS systems.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this VMS timesheet sync record was first created in the Staffing Hr lakehouse. Serves as the RECORD_AUDIT_CREATED timestamp for data lineage and audit trail purposes.',
    `dt_hours` DECIMAL(18,2) COMMENT 'Total double-time (DT) hours recorded on the timesheet being synchronized, applicable in states such as California where DT is mandated for hours beyond 12 in a day or 8 on the 7th consecutive day. Ensures accurate billing and payroll at DT rates.',
    `error_code` STRING COMMENT 'The error code returned by the VMS platform or integration middleware when a sync attempt fails or is rejected. Used for automated error classification, retry logic routing, and integration support triage. Null when sync_status is synced.',
    `error_message` STRING COMMENT 'Human-readable error description returned by the VMS platform or integration layer when a sync fails or is rejected. Provides context for manual investigation and resolution of failed sync events. Null when sync_status is synced.',
    `field_mapping_discrepancies` STRING COMMENT 'A structured description of specific field-level mismatches identified between the Kronos Workforce Ready timesheet and the VMS timesheet record (e.g., cost center code mismatch, job code mismatch, worker ID format difference). Stored as a delimited string of field names with discrepancy details. Used for root-cause analysis and integration mapping corrections.',
    `hours_variance` DECIMAL(18,2) COMMENT 'The difference between vms_total_hours and total_hours (VMS hours minus Kronos hours). A non-zero value indicates a discrepancy requiring reconciliation. Positive values mean the VMS recorded more hours; negative values mean Kronos recorded more hours. Used to prioritize reconciliation effort and assess billing risk.',
    `integration_batch_ref` STRING COMMENT 'The batch or job run identifier from the integration middleware that processed this sync record. Used for operational troubleshooting, replay of failed batches, and integration audit trails. Distinct from internal ETL metadata — this is a business-visible integration reference used by the integration operations team.',
    `kronos_timesheet_ref_code` STRING COMMENT 'The internal timesheet identifier as assigned by Kronos Workforce Ready. Used to cross-reference the internal time-and-attendance record with the VMS record during reconciliation and audit.',
    `last_retry_timestamp` TIMESTAMP COMMENT 'The date and time of the most recent retry attempt for this synchronization record. Used alongside retry_count to calculate retry intervals, enforce exponential backoff policies, and identify stale failed syncs requiring manual intervention.',
    `manual_override_by` STRING COMMENT 'The username or employee identifier of the Staffing Hr operator who applied the manual override to this sync record. Required for SOC 2 audit trail and accountability. Populated only when manual_override_flag is True.',
    `manual_override_flag` BOOLEAN COMMENT 'Indicates whether a human operator manually overrode the automated sync result for this record (True = manual override applied; False = automated sync result). Manual overrides are required when automated reconciliation cannot resolve discrepancies. Triggers enhanced audit logging per SOC 2 controls.',
    `manual_override_reason` STRING COMMENT 'Free-text explanation provided by the operator when a manual override is applied to this sync record. Required when manual_override_flag is True. Documents the business justification for the override for audit and compliance purposes.',
    `ot_hours` DECIMAL(18,2) COMMENT 'Total overtime (OT) hours recorded on the timesheet being synchronized, typically hours worked beyond 40 per week or 8 per day per FLSA or applicable state law. Critical for accurate billing at OT bill rates and worker compensation at OT pay rates.',
    `pay_rate` DECIMAL(18,2) COMMENT 'The hourly pay rate for the contingent worker associated with this timesheet, as recorded in the payroll system. Used alongside bill_rate to calculate spread and gross margin. Confidential compensation data.',
    `per_diem_amount` DECIMAL(18,2) COMMENT 'The per diem (daily expense allowance) amount included in this timesheet record, if applicable. Per diem is a non-taxable reimbursement for meals and incidentals for workers on travel assignments. Must be reconciled between Kronos and VMS to ensure accurate billing and payroll.',
    `reconciliation_outcome` STRING COMMENT 'The final outcome of the reconciliation process for this sync record. matched = hours match exactly with no intervention; reconciled = discrepancy resolved through manual or automated correction; unresolved = discrepancy remains open; escalated = referred to billing dispute team; voided = timesheet voided and excluded from billing. Critical for billing dispute management and MSP program reporting.. Valid values are `matched|reconciled|unresolved|escalated|voided`',
    `reconciliation_timestamp` TIMESTAMP COMMENT 'The date and time when the reconciliation outcome was determined and recorded for this sync record. Used for SLA measurement of reconciliation cycle time and billing cutoff compliance.',
    `regular_hours` DECIMAL(18,2) COMMENT 'Total regular (straight-time) hours recorded on the timesheet being synchronized. Used to verify that regular hours match between Kronos Workforce Ready and the VMS platform to prevent billing disputes.',
    `retry_count` STRING COMMENT 'The number of times this synchronization has been retried after an initial failure. Used to enforce maximum retry thresholds, trigger escalation workflows, and measure integration reliability. A high retry count may indicate a systemic VMS connectivity or data mapping issue.',
    `sync_direction` STRING COMMENT 'Indicates the direction of the timesheet data flow: push means Kronos Workforce Ready is sending hours to the VMS, pull means the VMS-approved timesheet is being retrieved into Kronos. Determines the authoritative source for reconciliation.. Valid values are `push|pull`',
    `sync_status` STRING COMMENT 'Current lifecycle state of this timesheet synchronization attempt. pending = awaiting processing; synced = successfully matched in both systems; failed = technical error prevented sync; rejected = VMS rejected the timesheet data; partial = some fields synced but discrepancies remain. This is the LIFECYCLE_STATUS for the sync transaction.. Valid values are `pending|synced|failed|rejected|partial`',
    `sync_timestamp` TIMESTAMP COMMENT 'The date and time when this synchronization attempt was executed. Represents the BUSINESS_EVENT_TIMESTAMP — the principal real-world event time of the sync operation. Stored in ISO 8601 format with timezone offset.',
    `timesheet_source_system` STRING COMMENT 'Identifies the authoritative source system from which the timesheet data originated for this sync event. Kronos = Kronos Workforce Ready is the source of record; VMS = the client VMS platform is the source of record (pull scenario); Manual = hours were entered manually outside of either system. Used for data lineage and audit.. Valid values are `Kronos|VMS|Manual`',
    `total_hours` DECIMAL(18,2) COMMENT 'Total billable hours on the timesheet (sum of regular, OT, and DT hours) as recorded in the source system. Used as the primary reconciliation figure between Kronos Workforce Ready and the VMS platform. Discrepancies in this field trigger billing dispute workflows.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this VMS timesheet sync record was last modified, such as after a retry, manual override, or reconciliation outcome update. Serves as the RECORD_AUDIT_UPDATED timestamp.',
    `vms_approved_timestamp` TIMESTAMP COMMENT 'The date and time when the client manager approved the timesheet within the VMS platform. Marks the point at which hours become billable and payable. Used for Time-to-Approve (TTA) SLA reporting and billing cycle cutoff determination.',
    `vms_approver_name` STRING COMMENT 'The name of the client manager or supervisor who approved or rejected the timesheet within the VMS platform. Required for audit trail, dispute resolution, and SLA compliance reporting under MSP/VMS program agreements.',
    `vms_job_ref_code` STRING COMMENT 'The job or requisition identifier as assigned by the client VMS platform. Used to associate the synced timesheet with the correct VMS job order or requisition for cost center allocation and client billing.',
    `vms_platform` STRING COMMENT 'Name of the client Vendor Management System (VMS) platform involved in this synchronization event. Identifies whether the sync is with Beeline, SAP Fieldglass, VNDLY, Coupa, Workday, or another VMS. Critical for platform-specific error handling and integration routing. [ENUM-REF-CANDIDATE: Beeline|Fieldglass|VNDLY|Coupa|Workday|Other — promote to reference product if additional platforms are onboarded]. Valid values are `Beeline|Fieldglass|VNDLY|Coupa|Workday|Other`',
    `vms_timesheet_ref_code` STRING COMMENT 'The external timesheet identifier assigned by the client VMS platform (e.g., Beeline timesheet number, Fieldglass time sheet ID). Used for cross-system reconciliation and billing dispute resolution. This is the BUSINESS_IDENTIFIER for the sync transaction as known externally.',
    `vms_total_hours` DECIMAL(18,2) COMMENT 'Total hours as recorded or approved within the client VMS platform for this timesheet period. Compared against total_hours from Kronos to identify discrepancies. A mismatch between this field and total_hours is the primary trigger for reconciliation workflows and billing dispute escalation.',
    `vms_worker_ref_code` STRING COMMENT 'The worker identifier as assigned by the client VMS platform (e.g., Beeline worker ID, Fieldglass contingent worker number). Used to map the internal worker record to the VMS worker profile during sync and reconciliation. Distinct from the internal worker_id.',
    `work_week_end_date` DATE COMMENT 'The end date of the work week covered by the timesheet being synchronized. Together with work_week_start_date, defines the exact pay period for payroll and billing reconciliation.',
    `work_week_start_date` DATE COMMENT 'The start date of the work week covered by the timesheet being synchronized. Used to align the sync record with the correct pay period and billing cycle for payroll processing and client invoicing.',
    CONSTRAINT pk_vms_timesheet_sync PRIMARY KEY(`vms_timesheet_sync_id`)
) COMMENT 'Tracks the bidirectional synchronization and reconciliation of timesheet records between the internal Kronos Workforce Ready system and client Vendor Management System (VMS) platforms such as Beeline, Fieldglass, VNDLY, or Coupa. Captures the VMS platform identifier, VMS timesheet reference ID, sync direction (push/pull), sync status (pending, synced, failed, rejected, partial), sync timestamp, error codes, field-level mapping discrepancies, retry count, manual override flags, and reconciliation outcome. Critical for MSP/VMS-managed programs where client approval occurs within the VMS portal and hours must match exactly between systems to avoid billing disputes.';

